-- Bỏ topic 'Grammar & Function Words'. Mỗi bộ <= 50 từ. Tổng: 638 từ.
-- UUID cố định (uuid5) => chạy lại an toàn (ON CONFLICT DO NOTHING).
-- ============================================================

-- 1) Nới ràng buộc: cho phép NHIỀU desk hệ thống cùng CEFR, miễn khác title.
DROP INDEX IF EXISTS uq_desk_global_cefr;
CREATE UNIQUE INDEX IF NOT EXISTS uq_desk_global_cefr_title
    ON desk (cefr_level, title) WHERE owner_id IS NULL;

-- 2) Dọn 6 desk hệ thống RỖNG cũ (V2): 'Desk A1'..'Desk C2', owner NULL, không có flashcard.
DELETE FROM desk
 WHERE owner_id IS NULL
   AND title IN ('Desk A1','Desk A2','Desk B1','Desk B2','Desk C1','Desk C2')
   AND NOT EXISTS (SELECT 1 FROM flashcard f WHERE f.desk_id = desk.id);

