    ('bc0c23e3-c810-5792-9c3e-eac82778d09f', '56008835-45df-5662-9b03-bb4114322db7', 'parent', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɛəɹənt/', 'audio/parent.mp3', 'One of the two persons from whom one is immediately biologically descended; a mother or father.', NULL, 'Family & Relationships', 'cha mẹ', 'Một trong hai người mà một người được sinh ra trực tiếp về mặt sinh học; mẹ hoặc cha.', NULL),
