    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('f3c1e9be-01de-5cbd-980e-dfe8785837f2', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'after', 'A1', '["prep", "conj", "adv"]'::jsonb, '[{"pos": "prep", "level": "A1"}, {"pos": "conj", "level": "A1"}, {"pos": "adv", "level": "A2"}]'::jsonb, '/ˈæf.tə(ɹ)/', 'audio/after.mp3', 'Later; second (of two); next, following, subsequent', 'The after gun is abaft the forward gun.', 'Time & Daily Routine', 'sau', 'Sau; thứ hai (trong hai); tiếp theo, kế tiếp, sau đó.', 'Khẩu pháo phía sau nằm ở phía sau khẩu pháo phía trước.'),
    ('6306be09-39ae-55d6-847e-e23f729e19a5', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'again', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/əˈɡeɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/again-uk.mp3', 'Another time; once more.', 'Great, thanks again!', 'Time & Daily Routine', 'lại, một lần nữa', 'Một lần nữa; thêm một lần nữa.', 'Tuyệt, cảm ơn một lần nữa!'),
    ('b14a5dda-13f9-5890-bff4-ee5c992a6bbd', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'age', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/eɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/age-us.mp3', 'The whole duration of a being, whether animal, plant, or other kind, being alive.', 'the age of infancy', 'Time & Daily Routine', 'tuổi tác', 'Toàn bộ thời gian tồn tại của một sinh vật, cho dù là động vật, thực vật, hoặc loại khác, khi còn sống.', 'tuổi ấu thơ'),
    ('9acf4182-bee3-5b18-96ba-9dd1f664c7b7', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'ago', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/əˈɡəʊ/', 'audio/ago.mp3', 'Gone; gone by; gone away; passed; passed away.', 'in days ago/in days agone', 'Time & Daily Routine', 'trước đây', 'Đã qua; đã trôi qua; đã đi qua; đã qua; đã trôi qua.', 'trong những ngày đã qua'),
    ('960a0a26-9eb5-5da8-a705-1ea38e9e23ac', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'begin', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/biˈɡɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/begin-uk.mp3', 'Beginning; start.', 'I began playing the piano at the age of five. Now that everyone is here, we should begin the presentation.', 'Time & Daily Routine', 'bắt đầu', 'Sự bắt đầu; khởi đầu.', 'Tôi bắt đầu chơi piano lúc năm tuổi. Bây giờ mọi người đã có mặt, chúng ta nên bắt đầu bài thuyết trình.'),
    ('e49e6a60-3615-545d-8299-260e09143db8', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'beginning', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɪˈɡɪn.ɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/beginning-us.mp3', 'The act of doing that which begins anything; commencement of an action, state, or space of time; entrance into being or upon a course; the first act, effort, or state of a succession of acts or states.', 'What was the beginning of the dispute?', 'Time & Daily Routine', 'khởi đầu', 'Hành động bắt đầu bất cứ điều gì; sự khởi đầu của một hành động, trạng thái, hoặc khoảng thời gian; bước vào sự tồn tại hoặc một quá trình; hành động, nỗ lực, hoặc trạng thái đầu tiên trong một chuỗi các hành động hoặc trạng thái', 'Điều gì đã khởi đầu cho cuộc tranh cãi?'),
    ('e4f033c7-8cb1-59a9-ab50-f74b0ce9891f', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'busy', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈbɪzi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/busy-uk.mp3', 'A police officer.', 'On my vacation I''ll busy myself with gardening.', 'Time & Daily Routine', 'bận rộn', 'Một cảnh sát.', 'Trong kỳ nghỉ, tôi sẽ bận rộn với việc làm vườn.'),
    ('2cfd2576-84c4-5ec6-8707-9dbfce51c7cc', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'carry', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/ˈkæ.ɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/carry.mp3', 'A manner of transporting or lifting something; the grip or position in which something is carried.', 'Adjust your carry from time to time so that you don''t tire too quickly.', 'Time & Daily Routine', 'mang, vác', 'Cách thức vận chuyển hoặc nâng một vật; cách cầm hoặc vị trí mà vật đó được mang.', 'Thỉnh thoảng hãy điều chỉnh cách mang của bạn để không mệt quá nhanh.'),
    ('7f44d383-4025-52b1-a1dd-6c101a3e9027', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'century', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsɛn.t͡ʃə.ɹiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/century-au.mp3', 'A period of 100 consecutive years; often specifically a numbered period with conventional start and end dates, e.g., the twentieth century, which stretches from (strictly) 1901 through 2000, or (informally) 1900 through 1999. The first century AD was from 1 to 100.', 'That was his tenth professional century.', 'Time & Daily Routine', 'thế kỷ', 'Một khoảng thời gian 100 năm liên tiếp; thường cụ thể là một giai đoạn được đánh số với ngày bắt đầu và kết thúc quy ước, ví dụ: thế kỷ hai mươi, kéo dài từ (chính xác) 1901 đến 2000, hoặc (thông tin', 'Đó là thế kỷ thứ mười trong sự nghiệp chuyên nghiệp của anh ấy.'),
    ('479479ce-d86b-571d-b2ad-f0d5deda4763', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'change', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/tʃeɪndʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/change-uk.mp3', 'The process of becoming different.', 'The product is undergoing a change in order to improve it.', 'Time & Daily Routine', 'thay đổi', 'Quá trình trở nên khác biệt.', 'Sản phẩm đang trải qua một sự thay đổi để cải thiện nó.'),
    ('d48a1e3f-b1f5-5bad-8b25-d0762688a868', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'day', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/deɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/day-us.mp3', 'Any period of 24 hours.', 'I''ve been here for two days and a bit.', 'Time & Daily Routine', 'ngày', 'Bất kỳ khoảng thời gian 24 giờ nào.', 'Tôi đã ở đây được hai ngày và một chút.'),
    ('ddb7325b-109c-5802-8c82-e814d9545ab2', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'during', 'A1', '["prep"]'::jsonb, '[{"pos": "prep", "level": "A1"}]'::jsonb, '/ˈdjɔː.ɹɪŋ/', 'audio/during.mp3', 'To last, continue, endure.', 'I lived with my parents during the 1970s.', 'Time & Daily Routine', 'trong suốt', 'Kéo dài, tiếp tục, tồn tại.', 'Tôi sống với bố mẹ trong suốt những năm 1970.'),
    ('4b1ebcce-9dd6-55fe-906b-bf9bcb4c5020', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'early', 'A1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/ˈɜː.li/', 'https://api.dictionaryapi.dev/media/pronunciations/en/early-uk.mp3', 'A shift (scheduled work period) that takes place early in the day.', 'at eleven, we went for an early lunch; she began reading at an early age; his mother suffered an early death', 'Time & Daily Routine', 'sớm', 'Một ca làm việc (thời gian làm việc theo lịch) diễn ra sớm trong ngày.', 'lúc mười một giờ, chúng tôi đi ăn trưa sớm; cô ấy bắt đầu đọc từ khi còn nhỏ; mẹ anh ấy qua đời sớm'),
    ('7f82525d-f1c1-577d-89b7-e165825b3846', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'end', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ɛnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/end-au.mp3', 'The terminal point of something in space or time.', 'At the end of the road, turn left.', 'Time & Daily Routine', 'kết thúc', 'Điểm cuối cùng của một cái gì đó trong không gian hoặc thời gian.', 'Ở cuối con đường, rẽ trái.'),
    ('79744f1c-1ee1-5b90-93b2-904d9903da38', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'evening', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈivnɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/evening-1-us.mp3', 'The time of the day between dusk and night, when it gets dark.', 'It was the evening of the Roman Empire.', 'Time & Daily Routine', 'buổi tối', 'Thời gian trong ngày giữa hoàng hôn và ban đêm, khi trời tối.', 'Đó là buổi chiều tàn của Đế chế La Mã.'),
    ('713a07cb-32e4-5bf1-a4f5-2ed1b20e2fa8', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'fall', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/fɔːl/', 'audio/fall.mp3', 'The act of moving to a lower position under the effect of gravity.', 'the fall of Rome', 'Time & Daily Routine', 'mùa thu', 'Hành động di chuyển đến một vị trí thấp hơn dưới tác dụng của trọng lực.', 'sự sụp đổ của La Mã'),
    ('fff687f6-9d65-5883-8ec1-1e0d2fd79b03', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'finish', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈfɪnɪʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/finish-uk.mp3', 'An end; the end of anything.', 'The car''s finish was so shiny and new.', 'Time & Daily Routine', 'kết thúc', 'Sự kết thúc; điểm cuối của bất cứ thứ gì.', 'Lớp hoàn thiện của chiếc xe thật bóng và mới.'),
    ('9dede65b-5d71-5061-a92b-d8332faaf721', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'future', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ˈfjuːt͡ʃə/', 'audio/future.mp3', 'The time ahead; those moments yet to be experienced.', 'There is no future in dwelling on the past.', 'Time & Daily Routine', 'tương lai', 'Thời gian phía trước; những khoảnh khắc chưa được trải nghiệm.', 'Không có tương lai trong việc đắm chìm vào quá khứ.'),
    ('535f70f7-6ecc-5380-a1f4-dd260ec68576', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'happen', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/ˈhæpən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/happen-us.mp3', 'To occur or take place.', 'Let me tell you how it happened.', 'Time & Daily Routine', 'xảy ra', 'Xuất hiện hoặc diễn ra.', 'Để tôi kể bạn nghe chuyện đã xảy ra thế nào.'),
    ('98ddff44-b42b-5c60-996c-38235fe497b0', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'hour', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈaʊɚ/', 'audio/hour.mp3', 'A time period of sixty minutes; one twenty-fourth of a day.', 'I spent an hour at lunch.', 'Time & Daily Routine', 'giờ', 'Một khoảng thời gian sáu mươi phút; một phần hai mươi tư của một ngày.', 'Tôi đã dành một giờ để ăn trưa.'),
    ('88607906-5310-544c-ade7-c584ada2390a', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'late', 'A1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/leɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/late-uk.mp3', 'A shift (scheduled work period) that takes place late in the day or at night.', 'It was late in the evening when we finally arrived.', 'Time & Daily Routine', 'muộn', 'Một ca làm việc (thời gian làm việc theo lịch) diễn ra vào cuối ngày hoặc ban đêm.', 'Đã muộn vào buổi tối khi chúng tôi cuối cùng cũng đến nơi.'),
    ('1affef18-4ac3-5607-9d09-3f89678888df', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'later', 'A1', '["adv", "adj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ˈleɪtə/', 'audio/later.mp3', 'Near the end of a period of time.', 'It was late in the evening when we finally arrived.', 'Time & Daily Routine', 'sau này', 'Gần cuối một khoảng thời gian.', 'Đã muộn vào buổi tối khi chúng tôi cuối cùng cũng đến nơi.'),
    ('86d461a4-82db-5416-a33f-9fcca75df493', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'moment', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈməʊmənt/', 'audio/moment.mp3', 'A brief, unspecified amount of time.', 'Wait a moment, while I lock the front door.', 'Time & Daily Routine', 'khoảnh khắc', 'Một khoảng thời gian ngắn, không xác định.', 'Chờ một chút, trong khi tôi khóa cửa trước.'),
    ('bfe7e50d-4e18-5857-8ffd-8c8abc6e9f5d', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'month', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/mʌnθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/month-uk.mp3', 'A period into which a year is divided, historically based on the phases of the moon.', 'July is my favourite month.', 'Time & Daily Routine', 'tháng', 'Một khoảng thời gian mà một năm được chia thành, dựa trên các pha của mặt trăng.', 'Tháng Bảy là tháng yêu thích của tôi.'),
    ('b83963b1-036e-566e-9228-0e39600cfae3', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'morning', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmɔːnɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/morning-uk.mp3', 'The part of the day from dawn to noon.', 'I''ll see you tomorrow morning.', 'Time & Daily Routine', 'buổi sáng', 'Phần của ngày từ bình minh đến trưa.', 'Tôi sẽ gặp bạn vào sáng mai.'),
    ('c8e65521-4999-51f3-beff-11df2f953ba7', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'next', 'A1', '["adj", "adv", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/nɛkst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/next-us.mp3', 'The one that follows after this one.', 'Next, please, don''t hold up the queue!', 'Time & Daily Routine', 'tiếp theo', 'Cái theo sau cái này.', 'Tiếp theo, làm ơn, đừng làm tắc nghẽn hàng đợi!'),
    ('642a4fec-cda8-50dd-ada0-22c67a9f42ab', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'night', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/naɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/night-uk.mp3', 'The period between sunset and sunrise, when a location faces far away from the sun, thus when the sky is dark.', 'How do you sleep at night when you attack your kids like that!?', 'Time & Daily Routine', 'ban đêm', 'Khoảng thời gian giữa lúc mặt trời lặn và mọc, khi một địa điểm quay mặt ra xa mặt trời, do đó bầu trời tối.', 'Làm sao bạn ngủ được vào ban đêm khi bạn tấn công con cái mình như vậy!?'),
    ('b45b20d0-ef59-5e4e-98fe-497bf873c54b', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'now', 'A1', '["adv", "conj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "conj", "level": "B1"}]'::jsonb, '/naʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/now-uk.mp3', 'The present time.', 'Now is the right time.', 'Time & Daily Routine', 'bây giờ', 'Thời điểm hiện tại.', 'Bây giờ là thời điểm thích hợp.'),
    ('86f740e2-4e61-5bf2-8559-6ea757b27af1', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'often', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/ˈɑf(t)ən/', 'audio/often.mp3', 'Frequent.', 'I often walk to work when the weather is nice.', 'Time & Daily Routine', 'thường xuyên', 'Thường xuyên.', 'Tôi thường đi bộ đến chỗ làm khi thời tiết đẹp.'),
    ('0decffc7-428e-5558-a906-32d68507c757', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'once', 'A1', '["adv", "conj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "conj", "level": "B1"}]'::jsonb, '/wɒn(t)s/', 'audio/once.mp3', '(frequency) One and only one time.', 'I have only once eaten pizza.', 'Time & Daily Routine', 'một lần', '(tần suất) Một và chỉ một lần.', 'Tôi mới chỉ ăn pizza một lần.'),
    ('d63e56e7-8e21-5e20-9dea-94467bedeb7e', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'past', 'A1', '["adj", "n", "prep", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "n", "level": "A1"}, {"pos": "prep", "level": "A1"}, {"pos": "adv", "level": "A2"}]'::jsonb, '/pɑːst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/past-uk.mp3', 'To change place.', 'a book about a time machine that can transport people back into the past', 'Time & Daily Routine', 'quá khứ, qua', 'Thay đổi vị trí.', 'một cuốn sách về cỗ máy thời gian có thể đưa người ta trở về quá khứ'),
    ('c73316a0-a8ce-5807-9b85-9a7de96b88e9', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'period', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɪəɹɪəd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/period-us.mp3', 'A length of time.', 'There was a period of confusion following the announcement.', 'Time & Daily Routine', 'thời kỳ, giai đoạn', 'Một khoảng thời gian.', 'Có một giai đoạn hỗn loạn sau thông báo.'),
    ('0c5a0764-c970-5d57-a1c0-9afffd513ee2', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'present', 'A1', '["adj", "n", "v"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/pɹəˈzɛnt/', 'audio/present.mp3', 'The current moment or period of time.', 'The barbaric practice continues to the present day.', 'Time & Daily Routine', 'hiện tại', 'Khoảnh khắc hoặc khoảng thời gian hiện tại.', 'Tập tục man rợ đó vẫn tiếp diễn cho đến ngày nay.'),
    ('f0c53ab2-7c97-5fdc-8482-e69eaba8743c', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'quickly', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/ˈkwɪkli/', 'https://api.dictionaryapi.dev/media/pronunciations/en/quickly-us.mp3', 'Rapidly; with speed; fast.', 'If we go this way, we''ll get there quickly.', 'Time & Daily Routine', 'một cách nhanh chóng', 'Một cách nhanh chóng; với tốc độ; nhanh.', 'Nếu chúng ta đi đường này, chúng ta sẽ đến đó nhanh thôi.'),
    ('8eac353a-8c50-55b2-b0b1-06c22c14f10a', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'ready', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈɹɛdi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ready-uk.mp3', 'Ready money; cash', 'The porridge is ready to serve.', 'Time & Daily Routine', 'sẵn sàng', 'Tiền mặt sẵn có; tiền mặt', 'Cháo đã sẵn sàng để dọn ra.'),
    ('9602d1e9-b725-55d3-b308-4edf4337c4fa', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'routine', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ɹuːˈtiːn/', 'audio/routine.mp3', 'A course of action to be followed regularly; a standard procedure.', 'Connie was completely robotic and emotionless by age 12; her entire life had become one big routine.', 'Time & Daily Routine', 'thói quen', 'Một chuỗi hành động được thực hiện thường xuyên; một quy trình tiêu chuẩn.', 'Connie hoàn toàn như người máy và vô cảm vào năm 12 tuổi; toàn bộ cuộc đời cô đã trở thành một thói quen lớn.'),
    ('7db3daf9-170b-5f55-851e-7572784ee308', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'sit', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/sɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sit-au.mp3', 'Subsidence of the roof of a coal mine.', 'After a long day of walking, it was good just to sit and relax.', 'Time & Daily Routine', 'ngồi', 'Sự lún xuống của mái nhà trong một mỏ than.', 'Sau một ngày dài đi bộ, thật tốt khi chỉ cần ngồi xuống và thư giãn.'),
    ('8cf8da25-ebdd-5e98-9bc0-46f0c09f6cd7', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'sometimes', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/ˈsʌmtaɪmz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sometimes-us.mp3', 'Former; sometime.', 'Sometimes I sit and think, but mostly I just sit.', 'Time & Daily Routine', 'đôi khi', 'Trước đây; đã có lúc.', 'Đôi khi tôi ngồi và suy nghĩ, nhưng phần lớn tôi chỉ ngồi thôi.'),
    ('7e344df7-6331-5d56-9e27-9b79cfc2bd7b', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'soon', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/suːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/soon-us.mp3', 'Short in length of time from the present.', 'I need the soonest date you have available.', 'Time & Daily Routine', 'sớm', 'Ngắn về khoảng thời gian từ hiện tại.', 'Tôi cần ngày sớm nhất mà anh có.'),
    ('29c2a21f-4345-5e90-abbb-3bfe70e81a31', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'start', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/stɑːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/start-uk.mp3', 'The beginning of an activity.', 'The movie was entertaining from start to finish.', 'Time & Daily Routine', 'bắt đầu', 'Sự khởi đầu của một hoạt động.', 'Bộ phim rất giải trí từ đầu đến cuối.'),
    ('4d08fece-b128-5580-a5fb-5d4bedf1136e', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'still', 'A1', '["adv", "adj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/stɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/still-uk.mp3', 'A period of calm or silence.', 'the still of the night', 'Time & Daily Routine', 'yên tĩnh', 'Một khoảng thời gian yên lặng hoặc tĩnh mịch.', 'sự yên tĩnh của màn đêm'),
    ('cfcf5b5d-da11-557a-9e38-8c87b641bdd6', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'time', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/tɑem/', 'https://api.dictionaryapi.dev/media/pronunciations/en/time-au.mp3', 'The inevitable progression into the future with the passing of present and past events.', 'Time stops for nobody. the ebb and flow of time', 'Time & Daily Routine', 'thời gian', 'Sự tiến triển không thể tránh khỏi vào tương lai với sự trôi qua của các sự kiện hiện tại và quá khứ.', 'Thời gian không chờ đợi ai. sự lên xuống của thời gian'),
    ('23d9c028-766d-5712-99d4-5db5ed463404', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'today', 'A1', '["adv", "n"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/təˈdeɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/today-uk.mp3', 'A current day or date.', 'Today is the day we''ll fix this once and for all.', 'Time & Daily Routine', 'hôm nay', 'Một ngày hoặc ngày tháng hiện tại.', 'Hôm nay là ngày chúng ta sẽ sửa chữa việc này một lần và mãi mãi.'),
    ('24050cb5-052b-54e8-97dc-9ed698ef4773', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'tomorrow', 'A1', '["adv", "n"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/təˈmɔɹoʊ/', 'audio/tomorrow.mp3', 'The day after the present day.', 'If you don''t get your life on track today, you''re going to be very sorry tomorrow.', 'Time & Daily Routine', 'ngày mai', 'Ngày sau ngày hiện tại.', 'Nếu bạn không sắp xếp cuộc sống của mình vào hôm nay, bạn sẽ rất hối hận vào ngày mai.'),
    ('af448488-5a94-5868-a69b-1d81c6bd37e6', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'tonight', 'A1', '["adv", "n"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/təˈnaɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tonight-us.mp3', 'The nighttime of the current day or date; this night.', 'I have high hopes for tonight.', 'Time & Daily Routine', 'tối nay', 'Buổi tối của ngày hoặc ngày tháng hiện tại; đêm nay.', 'Tôi có nhiều hy vọng cho tối nay.'),
    ('55fa04ea-f3a2-53f8-8e2b-d85e9768956d', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'usually', 'A1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A1"}]'::jsonb, '/ˈjuːʒju(ə)li/', 'audio/usually.mp3', 'Most of the time; less than always, but more than occasionally.', 'Except for one or two days a year, he usually walks to work.', 'Time & Daily Routine', 'thường thường', 'Phần lớn thời gian; ít hơn luôn luôn, nhưng nhiều hơn thỉnh thoảng.', 'Trừ một hoặc hai ngày trong năm, anh ấy thường đi bộ đến chỗ làm.'),
    ('658f49fb-fe11-52ef-a493-6d6992493820', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'wait', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/weɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wait-uk.mp3', 'A delay.', 'I had a very long wait at the airport security check.', 'Time & Daily Routine', 'chờ đợi', 'Sự chậm trễ.', 'Tôi đã phải chờ đợi rất lâu tại trạm kiểm soát an ninh sân bay.'),
    ('bfb5a185-62ff-52fd-961a-8e2c4fe5e2b7', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'wake', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/ˈweɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wake-us.mp3', 'The act of waking, or state of being awake.', 'I woke up at four o''clock this morning.', 'Time & Daily Routine', 'thức dậy', 'Hành động thức dậy, hoặc trạng thái tỉnh táo.', 'Tôi thức dậy lúc bốn giờ sáng nay.'),
    ('90080ec6-96e2-5e5e-9e2c-f747ab3d3c3e', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'watch', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/wɒt͡ʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/watch-uk.mp3', 'A portable or wearable timepiece.', 'More people today carry a watch on their wrists than in their pockets.', 'Time & Daily Routine', 'đồng hồ đeo tay', 'Đồng hồ đeo tay hoặc mang theo được.', 'Ngày nay nhiều người đeo đồng hồ trên cổ tay hơn là trong túi.'),
    ('c707cf0f-2c4b-552c-9e22-47d1d6f0d578', '63f38018-e5dc-54c4-b229-cfc5ea3547db', 'week', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/wiːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/week-uk.mp3', 'Any period of seven consecutive days.', 'A 4-day week consists of Monday, Tuesday, Wednesday, and Thursday.', 'Time & Daily Routine', 'tuần', 'Bất kỳ khoảng thời gian nào gồm bảy ngày liên tiếp.', 'Một tuần làm việc 4 ngày bao gồm Thứ Hai, Thứ Ba, Thứ Tư và Thứ Năm.')
