    ('06528157-268a-5ae0-b9e4-5ae76f45f124', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'bottle', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbɑ.təl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bottle-ca.mp3', 'A container, typically made of glass or plastic and having a tapered neck, used primarily for holding liquids.', 'Beer is often sold in bottles.', 'Food & Drink', 'chai', 'Một vật chứa, thường làm bằng thủy tinh hoặc nhựa và có cổ thon, chủ yếu dùng để đựng chất lỏng.', 'Bia thường được bán trong chai.'),
    ('6576cc9d-6fc6-54d8-9743-b1993614e0c1', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'breakfast', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbɹɛkfəst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/breakfast-uk.mp3', 'The first meal of the day, usually eaten in the morning.', 'You should put more protein in her breakfast so she will grow.', 'Food & Drink', 'bữa sáng', 'Bữa ăn đầu tiên trong ngày, thường ăn vào buổi sáng.', 'Bạn nên cho thêm protein vào bữa sáng của cô ấy để cô ấy phát triển.'),
    ('53b7f9f4-d3b5-5366-82b5-3caa26076939', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'butter', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbʊtə/', 'audio/butter.mp3', 'A soft, fatty foodstuff made by churning the cream of milk (generally cow''s milk).', 'peanut butter', 'Food & Drink', 'bơ', 'Một thực phẩm mềm, béo được làm bằng cách khuấy kem của sữa (thường là sữa bò).', 'bơ đậu phộng'),
    ('e6693028-e0ff-5ffe-910f-867c235d5892', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'cafe', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkæfeɪ/', 'audio/cafe.mp3', 'A convenience store, originally one that sold coffee and similar basic items.', '1982, Joni Mitchell, Chinese Café / Unchained Melody (song)', 'Food & Drink', 'quán cà phê', 'Một cửa hàng tiện lợi, ban đầu là nơi bán cà phê và các mặt hàng cơ bản tương tự.', '1982, Joni Mitchell, Chinese Café / Unchained Melody (bài hát)'),
    ('1c8c3ff9-d545-5f55-b7de-f60f3d019e24', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'cake', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/keɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cake-1-uk.mp3', 'A rich, sweet dessert food, typically made of flour, sugar and eggs and baked in an oven, and often covered in icing.', 'a johnnycake', 'Food & Drink', 'bánh ngọt', 'Một loại thực phẩm tráng miệng ngọt và phong phú, thường được làm từ bột mì, đường và trứng và nướng trong lò, và thường được phủ kem.', 'bánh ngô'),
    ('b32b39df-d652-52e3-b9bf-6895943e50dd', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'cheese', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/t͡ʃiz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cheese-us.mp3', 'A dairy product made from curdled or cultured milk.', 'Say "cheese"! ... and there we are!', 'Food & Drink', 'phô mai', 'Một sản phẩm từ sữa được làm từ sữa đông hoặc sữa lên men.', 'Nói "cheese"! ... và thế là xong!'),
    ('8fb97920-4c0e-52fe-b609-b28a35ff2617', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'chicken', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈt͡ʃɪkɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chicken-uk.mp3', 'A domestic fowl, Gallus gallus, especially when young.', 'Why do you refuse to fight? Huh, I guess you''re just too chicken.', 'Food & Drink', 'gà', 'Một loài gia cầm, Gallus gallus, đặc biệt là khi còn non.', 'Tại sao bạn từ chối chiến đấu? Hừ, tôi đoán bạn chỉ là quá nhát gan thôi.'),
    ('cfefe82e-959f-59a8-ade1-5c512b5b5484', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'chocolate', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈt͡ʃɔk(ə)lət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chocolate-au.mp3', 'A food made from ground roasted cocoa beans.', 'Chocolate is a very popular treat.', 'Food & Drink', 'sô cô la', 'Một loại thực phẩm làm từ hạt ca cao rang xay.', 'Sô cô la là một món ăn vặt rất phổ biến.'),
    ('1499b091-c453-5555-9269-e0391e10f14e', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'coffee', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkɑ.fi/', 'audio/coffee.mp3', 'A beverage made by infusing the beans of the coffee plant in hot water.', 'He did not stay for coffee.', 'Food & Drink', 'cà phê', 'Một loại đồ uống được pha chế bằng cách ngâm hạt cây cà phê trong nước nóng.', 'Anh ấy không ở lại uống cà phê.'),
    ('ed5e89a0-da21-5074-9894-d080bfc000d7', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'cook', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/kuːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cook-au.mp3', 'A person who prepares food.', 'I''m a terrible cook, so I eat a lot of frozen dinners.', 'Food & Drink', 'nấu ăn / đầu bếp', 'Một người chuẩn bị thức ăn.', 'Tôi là một đầu bếp tồi, vì vậy tôi ăn rất nhiều bữa tối đông lạnh.'),
    ('2dc659cb-767a-55b6-b009-92a0f179edcf', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'cooking', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkʊ.kɪŋ/', 'audio/cooking.mp3', 'To prepare (food) for eating by heating it, often by combining it with other ingredients.', 'I''m cooking bangers and mash.', 'Food & Drink', 'nấu nướng', 'Chuẩn bị (thức ăn) để ăn bằng cách làm nóng nó, thường bằng cách kết hợp nó với các thành phần khác.', 'Tôi đang nấu xúc xích và khoai tây nghiền.'),
    ('0de68f7c-8a92-556d-8077-611e1684ffa4', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'cream', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/kɹiːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cream-us.mp3', 'The butterfat/milkfat part of milk which rises to the top; this part when separated from the remainder.', 'Take 100 ml of cream and 50 grams of sugar…', 'Food & Drink', 'kem', 'Phần chất béo sữa/kem của sữa nổi lên trên; phần này khi được tách ra khỏi phần còn lại.', 'Lấy 100 ml kem và 50 gram đường...'),
    ('77840c6a-7a9b-5df3-a7a1-41471f239da8', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'date', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/deɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/date-us.mp3', 'The fruit of the date palm, Phoenix dactylifera, somewhat in the shape of an olive, containing a soft, sweet pulp and enclosing a hard kernel.', 'We made a nice cake from dates.', 'Food & Drink', 'quả chà là', 'Quả của cây chà là, Phoenix dactylifera, hơi giống hình quả ô liu, chứa phần thịt mềm, ngọt và bao bọc một hạt cứng.', 'Chúng tôi đã làm một chiếc bánh ngon từ quả chà là.'),
    ('2042d6f3-f126-54c3-9211-a41d4bdc2693', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'delicious', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/dɪˈlɪʃəs/', 'audio/delicious.mp3', 'Pleasing to taste; tasty.', 'The irony is delicious!', 'Food & Drink', 'ngon', 'Làm hài lòng vị giác; ngon miệng.', 'Sự mỉa mai thật ngon lành!'),
    ('e540c443-66e4-583e-8e43-8a0d22a299e7', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'dinner', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈdɪnə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dinner-uk.mp3', 'A midday meal (in a context in which the evening meal is called supper or tea).', 'Give the dog its dinner.', 'Food & Drink', 'bữa tối', 'Một bữa ăn giữa ngày (trong ngữ cảnh mà bữa ăn tối được gọi là supper hoặc tea).', 'Cho con chó bữa tối của nó.'),
    ('0460beed-28df-526f-bfb5-a793e0e51999', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'dish', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/dɪʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dish-us.mp3', 'A vessel such as a plate for holding or serving food, often flat with a depressed region in the middle.', 'a dish of stew', 'Food & Drink', 'món ăn, đĩa', 'Vật đựng như một cái đĩa để đựng hoặc phục vụ thức ăn, thường phẳng với phần lõm ở giữa.', 'một đĩa món hầm'),
    ('66894810-66da-56b1-8fbb-da84df45a452', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'drink', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/dɹɪŋk/', 'audio/drink.mp3', 'To consume (a liquid) through the mouth.', 'He drank the water I gave him.', 'Food & Drink', 'đồ uống, uống', 'Tiêu thụ (một chất lỏng) qua miệng.', 'Anh ấy đã uống nước tôi đưa cho.'),
    ('fa7f5b97-f5aa-5d87-b55c-5168080bf121', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'eat', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/iːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/eat-uk.mp3', 'Something to be eaten; a meal; a food item.', 'What’s eating you?', 'Food & Drink', 'ăn', 'Thứ gì đó để ăn; một bữa ăn; một món ăn.', 'Có chuyện gì làm bạn bận tâm vậy?'),
    ('cbf8a401-9e02-576d-b3ad-aff990b2ef8a', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'egg', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/eɪɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/egg-us.mp3', 'An approximately spherical or ellipsoidal body produced by birds, reptiles, insects and other animals, housing the embryo during its development.', 'I also determine the minimal amount of egg required to make good mayonnaise.', 'Food & Drink', 'quả trứng', 'Một vật thể có hình cầu hoặc hình elip gần đúng được tạo ra bởi chim, bò sát, côn trùng và các động vật khác, chứa phôi thai trong quá trình phát triển của nó.', 'Tôi cũng xác định lượng trứng tối thiểu cần thiết để làm sốt mayonnaise ngon.'),
    ('6818a8ee-d3c5-5d0d-afdc-913bd1f6314e', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'fish', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/fɪʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fish-au.mp3', 'A cold-blooded vertebrate animal that lives in water, moving with the help of fins and breathing with gills.', 'Salmon is a fish.', 'Food & Drink', 'cá', 'Một loài động vật có xương sống máu lạnh sống trong nước, di chuyển bằng vây và thở bằng mang.', 'Cá hồi là một loại cá.'),
    ('a0999610-7fd1-5d25-a694-1f250000f985', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'food', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/fuːd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/food-uk.mp3', 'Any solid substance that can be consumed by living organisms, especially by eating, in order to sustain life.', 'The innkeeper brought them food and drink.', 'Food & Drink', 'thức ăn', 'Bất kỳ chất rắn nào có thể được tiêu thụ bởi các sinh vật sống, đặc biệt là bằng cách ăn, để duy trì sự sống.', 'Chủ quán trọ mang cho họ thức ăn và đồ uống.'),
    ('f11c9c0c-5f83-5619-8998-f4081597c55a', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'fruit', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/fɹuːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fruit-uk.mp3', '(often in the plural) In general, a product of plant growth useful to man or animals.', 'His long nights in the office eventually bore fruit when his business boomed and he was given a raise.', 'Food & Drink', 'trái cây', '(thường ở số nhiều) Nói chung, một sản phẩm của sự phát triển thực vật hữu ích cho con người hoặc động vật.', 'Những đêm dài làm việc tại văn phòng cuối cùng cũng mang lại kết quả khi công việc kinh doanh của anh ấy bùng nổ và anh ấy được tăng lương.'),
    ('c4279a89-ddc4-569e-9c84-c3d8c3e4c53a', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'juice', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/d͡ʒuːs/', 'audio/juice.mp3', 'A liquid from a plant, especially fruit.', 'Squeeze the orange and some juice will come out.', 'Food & Drink', 'nước ép', 'Chất lỏng từ thực vật, đặc biệt là trái cây.', 'Vắt quả cam và một ít nước ép sẽ chảy ra.'),
    ('5dae5350-adfa-56ae-b246-d15f65d54252', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'lunch', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/lʌnt͡ʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lunch-au.mp3', 'A light meal usually eaten around midday, notably when not as main meal of the day.', 'After the funeral there was a lunch for those who didn''t go to the cemetery.', 'Food & Drink', 'bữa trưa', 'Một bữa ăn nhẹ thường được ăn vào khoảng giữa trưa, đặc biệt khi không phải là bữa chính trong ngày.', 'Sau đám tang có một bữa trưa cho những người không đến nghĩa trang.'),
    ('488641fa-db02-5a12-8c11-397c510fd5bd', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'meal', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/miːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/meal-uk.mp3', 'Food that is prepared and eaten, usually at a specific time, and usually in a comparatively large quantity (as opposed to a snack).', 'Breakfast is the morning meal, lunch is the noon meal, and dinner, or supper, is the evening meal.', 'Food & Drink', 'bữa ăn', 'Thức ăn được chuẩn bị và ăn, thường vào một thời điểm cụ thể, và thường với số lượng tương đối lớn (trái ngược với bữa ăn nhẹ).', 'Bữa sáng là bữa ăn buổi sáng, bữa trưa là bữa ăn buổi trưa, và bữa tối là bữa ăn buổi tối.'),
    ('f4fd0c8e-4035-5053-9c59-a26c7220ecd8', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'meat', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/miːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/meat-uk.mp3', 'The flesh (muscle tissue) of an animal used as food.', 'A large portion of domestic meat production comes from animals raised on factory farms.', 'Food & Drink', 'thịt', 'Phần thịt (mô cơ) của động vật được dùng làm thức ăn.', 'Một phần lớn sản xuất thịt trong nước đến từ động vật được nuôi trong các trang trại công nghiệp.'),
    ('9f4b65fc-e11d-50cf-b0a0-5ca863a1c640', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'milk', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '[mɛlk]', 'audio/milk.mp3', 'A white liquid produced by the mammary glands of female mammals to nourish their young. From certain animals, especially cows, it is also called dairy milk and is a common food for humans as a beverage or used to produce various dairy products such as butter, cheese, and yogurt.', 'Table three ordered three milks. (Formally: The guests at table three ordered three glasses of milk.)', 'Food & Drink', 'sữa', 'Một chất lỏng màu trắng được sản xuất bởi tuyến vú của động vật có vú cái để nuôi con non. Từ một số động vật nhất định, đặc biệt là bò, nó còn được gọi là sữa bò và là một loại thực phẩm phổ biến cho con người như một loại đồ uống.', 'Bàn ba gọi ba sữa. (Trang trọng: Những vị khách ở bàn ba đã gọi ba ly sữa.)'),
    ('993f7bcf-94b6-5d07-a99a-06fe3daf39e4', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'pepper', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɛpə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pepper-uk.mp3', 'A plant of the family Piperaceae.', 'Some ballparks have signs saying "No pepper games".', 'Food & Drink', 'hạt tiêu', 'Một loại cây thuộc họ Piperaceae.', 'Một số sân bóng có biển báo "Không chơi trò pepper".'),
    ('9efc071c-de12-5762-84ba-15d381f2b271', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'pig', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɪɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pig-1-au.mp3', 'Any of several intelligent mammalian species of the genus Sus, having cloven hooves, bristles and a nose adapted for digging; especially the domesticated animal Sus scrofa.', 'The man kept a pen with two pigs that he fed from carrots to cabbage.', 'Food & Drink', 'con lợn', 'Bất kỳ loài động vật có vú thông minh nào thuộc chi Sus, có móng chẻ, lông cứng và mũi thích nghi để đào; đặc biệt là động vật đã thuần hóa Sus scrofa.', 'Người đàn ông nuôi hai con lợn trong chuồng mà ông ta cho ăn từ cà rốt đến bắp cải.'),
    ('919b64e4-f41d-5f0b-89bf-6fafb8f8cd4e', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'salt', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/sɔlt/', 'audio/salt.mp3', 'A common substance, chemically consisting mainly of sodium chloride (NaCl), used extensively as a condiment and preservative.', 'Attic salt', 'Food & Drink', 'muối', 'Một chất phổ biến, về mặt hóa học chủ yếu gồm natri clorua (NaCl), được sử dụng rộng rãi làm gia vị và chất bảo quản.', 'Muối Attic'),
    ('c5d219f8-2780-589d-9bc9-c08060594ae0', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'soup', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/suːp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/soup-uk.mp3', 'Any of various dishes commonly made by combining liquids, such as water or stock with other ingredients, such as meat and vegetables, that contribute flavor and texture.', 'Pho is a traditional Vietnamese soup.', 'Food & Drink', 'súp', 'Bất kỳ món ăn nào thường được chế biến bằng cách kết hợp chất lỏng, chẳng hạn như nước hoặc nước dùng với các thành phần khác, chẳng hạn như thịt và rau củ, để tạo thêm hương vị và kết cấu.', 'Phở là một món súp truyền thống của Việt Nam.'),
    ('0ce39a38-698f-58cb-8486-b4190b91645e', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'sugar', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈʃʊɡə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sugar-uk.mp3', 'Sucrose in the form of small crystals, obtained from sugar cane or sugar beet and used to sweeten food and drink.', 'He usually has his coffee white with one sugar.', 'Food & Drink', 'đường', 'Sucrose dưới dạng tinh thể nhỏ, thu được từ mía hoặc củ cải đường và được dùng để làm ngọt thực phẩm và đồ uống.', 'Anh ấy thường uống cà phê sữa với một viên đường.'),
    ('e3c13b78-1e90-5686-a149-5fa691bf1c2d', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'tea', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/tiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tea-1-uk.mp3', 'A drug smoked or ingested for euphoric effect, cannabis.', 'After smoking a bowl of that fine marijuana, they ate some brownies.', 'Food & Drink', 'trà', 'Một loại ma túy được hút hoặc uống để tạo cảm giác hưng phấn, cần sa.', 'Sau khi hút một tẩu cần sa ngon lành đó, họ ăn một ít bánh brownie.'),
    ('a8fd7407-d627-5519-8497-9ca407c1b51e', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'tomato', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '[tʰə̥ˈmɐːtʰɐʉ]', 'https://api.dictionaryapi.dev/media/pronunciations/en/tomato-au.mp3', 'A widely cultivated plant, Solanum lycopersicum, having edible fruit.', 'Lookit the legs on that hot tomato!', 'Food & Drink', 'cà chua', 'Một loại cây được trồng rộng rãi, Solanum lycopersicum, có quả ăn được.', 'Nhìn đôi chân của cô gái quyến rũ đó kìa!'),
    ('d8c940b1-2397-53c6-932d-e07469116804', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'waiter', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈweɪtə/', 'audio/waiter.mp3', 'A male or female attendant who serves customers at their tables in a restaurant, café or similar.', 'Waiter! There''s a fly in my soup.', 'Food & Drink', 'bồi bàn', 'Người phục vụ nam hoặc nữ phục vụ khách hàng tại bàn của họ trong nhà hàng, quán cà phê hoặc tương tự.', 'Bồi bàn! Có một con ruồi trong súp của tôi.'),
    ('e6036cfd-7938-53a9-a714-d5f1bada03ed', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'wine', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/waɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wine-uk.mp3', 'An alcoholic beverage made by fermenting the juice of grapes.', 'She ordered some wine for the meal.', 'Food & Drink', 'rượu vang', 'Đồ uống có cồn được làm bằng cách lên men nước ép từ nho.', 'Cô ấy gọi một ít rượu vang cho bữa ăn.'),
    ('e3b21d8c-872c-517f-9576-1cd091de9478', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'apple', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈæp.əl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/apple-uk.mp3', 'A common, round fruit produced by the tree Malus domestica, cultivated in temperate climates.', NULL, 'Food & Drink', 'quả táo', 'Một loại trái cây tròn phổ biến được sản xuất bởi cây Malus domestica, được trồng ở vùng khí hậu ôn đới.', NULL),
    ('05bac31b-2937-5bd7-9a25-740c1fbb28fa', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'banana', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bəˈnɑːnə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/banana-uk.mp3', 'An elongated curved tropical fruit that grows in bunches and has a creamy flesh and a smooth skin.', NULL, 'Food & Drink', 'quả chuối', 'Một loại trái cây nhiệt đới dài cong mọc thành nải, có thịt kem và vỏ mịn.', NULL),
    ('6455fe75-a117-55b8-8c03-30231a9e947a', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'bread', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɹeːd/', 'audio/bread.mp3', 'A foodstuff made by baking dough made from cereals.', NULL, 'Food & Drink', 'bánh mì', 'Thực phẩm được làm bằng cách nướng bột nhào từ ngũ cốc.', NULL),
    ('2fdbbf3b-740c-5e30-9f45-816d6fc870f9', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'carrot', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkæɹ.ət/', 'audio/carrot.mp3', 'A vegetable with a nutritious, juicy, sweet root that is often orange in colour, Daucus carota, especially the subspecies sativus in the family Apiaceae.', NULL, 'Food & Drink', 'cà rốt', 'Một loại rau có rễ bổ dưỡng, mọng nước, ngọt, thường có màu cam, Daucus carota, đặc biệt là phân loài sativus trong họ Apiaceae.', NULL),
    ('c9583100-f5db-596e-8beb-015e75471010', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'menu', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmɛnju/', 'https://api.dictionaryapi.dev/media/pronunciations/en/menu-us.mp3', 'The details of the food to be served at a banquet; a bill of fare.', NULL, 'Food & Drink', 'thực đơn', 'Chi tiết về thức ăn sẽ được phục vụ tại một bữa tiệc; một bảng kê món ăn.', NULL),
    ('4326a7d6-4bd8-5493-b1a6-f4e98cbb478e', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'onion', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈʌŋjɪn/', 'audio/onion.mp3', 'A monocotyledonous plant (Allium cepa), allied to garlic, used as vegetable and spice.', NULL, 'Food & Drink', 'củ hành', 'Một loài thực vật một lá mầm (Allium cepa), họ hàng với tỏi, được dùng làm rau và gia vị.', NULL),
    ('528a9501-3121-57be-821a-54829916f226', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'orange', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}]'::jsonb, '/ˈɔɹɪ̈nd͡ʒ/', 'audio/orange.mp3', 'An evergreen tree of the genus Citrus such as Citrus sinensis.', NULL, 'Food & Drink', 'quả cam', 'Một loại cây thường xanh thuộc chi Citrus như Citrus sinensis.', NULL),
    ('6a25f6eb-b769-5190-9477-fdfe757b150b', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'potato', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/pəˈteɪ.təʊ/', 'audio/potato.mp3', 'The tuber of a plant, Solanum tuberosum, eaten as a starchy vegetable, particularly in the Americas and Europe; this plant.', NULL, 'Food & Drink', 'khoai tây', 'Củ của cây Solanum tuberosum, được ăn như một loại rau giàu tinh bột, đặc biệt ở châu Mỹ và châu Âu; loại cây này.', NULL),
    ('9aec6716-80c7-575d-af4c-ce3df031e118', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'restaurant', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɹɛs.t(ə).ɹ(ə)nt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/restaurant-uk.mp3', 'An eating establishment in which diners are served food, usually by waiters at their tables but sometimes (as in a fast food restaurant) at a counter.', NULL, 'Food & Drink', 'nhà hàng', 'Một cơ sở ăn uống nơi thực khách được phục vụ thức ăn, thường bởi người phục vụ tại bàn nhưng đôi khi (như trong nhà hàng thức ăn nhanh) tại quầy.', NULL),
    ('1d412f52-2e0a-5a2d-9612-94f9e4da2b3f', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'rice', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɹaɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rice-uk.mp3', 'Cereal plants, Oryza sativa of the grass family whose seeds are used as food.', NULL, 'Food & Drink', 'gạo, cơm', 'Cây ngũ cốc, Oryza sativa thuộc họ cỏ có hạt được dùng làm thực phẩm.', NULL),
    ('9d536412-e733-5c9e-a11b-521f22542b93', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'salad', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsæləd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/salad-us.mp3', 'A food made primarily of a mixture of raw or cold ingredients, typically vegetables, usually served with a dressing such as vinegar or mayonnaise.', NULL, 'Food & Drink', 'sa lát', 'Một món ăn chủ yếu được làm từ hỗn hợp các nguyên liệu sống hoặc lạnh, thường là rau củ, thường được dùng kèm với nước sốt như giấm hoặc mayonnaise.', NULL),
    ('88a2abf3-6b89-5c03-89c3-f59bf4aac476', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'sandwich', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsæmwɪd͡ʒ/', 'audio/sandwich.mp3', 'A dish or foodstuff where two or more slices of bread serve as the wrapper or container of some other food.', NULL, 'Food & Drink', 'bánh sandwich', 'Một món ăn hoặc thực phẩm trong đó hai hoặc nhiều lát bánh mì đóng vai trò là lớp bọc hoặc hộp đựng cho một số thực phẩm khác.', NULL),
    ('9b994aeb-1e00-50fc-b904-0b7033606b74', 'a2ea8616-ee5c-5880-b62f-bf7fb8f2f4f7', 'vegetable', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈvɛd͡ʒtəbəl/', 'audio/vegetable.mp3', 'Any plant.', NULL, 'Food & Drink', 'rau củ', 'Bất kỳ loại cây trồng nào.', NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

