INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('34078848-d5e4-5648-8f89-dff8fb98bcbe', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'bath', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɐːθ/', 'audio/bath.mp3', 'A tub or pool which is used for bathing: bathtub.', 'a bath of heated sand, ashes, steam, or hot air', 'Home & Living', 'bồn tắm', 'Một bồn hoặc bể được sử dụng để tắm: bồn tắm.', 'một bồn cát nóng, tro, hơi nước, hoặc không khí nóng'),
    ('241b5df7-3002-5f15-8c3f-ae8e93f241b5', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'bathroom', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbæθ.ɹuːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bathroom-uk.mp3', 'A room containing a shower and/or bathtub, and (typically but not necessarily) a toilet.', 'Most Americans don''t know ''WC'' and many Brits mock ''bathroom'' but almost everyone understands ''toilet'' or ''lavatory''.', 'Home & Living', 'phòng tắm', 'Một phòng có vòi sen và/hoặc bồn tắm, và (thường nhưng không nhất thiết) một nhà vệ sinh.', 'Hầu hết người Mỹ không biết ''WC'' và nhiều người Anh chế giễu ''bathroom'' nhưng hầu như ai cũng hiểu ''toilet'' hoặc ''lavatory''.'),
    ('9d1dc8bd-a1e1-54a2-a9dd-cfd3a6eba9a5', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'bed', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bed/', 'audio/bed.mp3', 'A piece of furniture, usually flat and soft, on which to rest or sleep.', 'My cat often sleeps on my bed. I keep a glass of water next to my bed when I sleep.', 'Home & Living', 'giường', 'Một món đồ nội thất, thường phẳng và mềm, để nghỉ ngơi hoặc ngủ.', 'Con mèo của tôi thường ngủ trên giường tôi. Tôi để một ly nước cạnh giường khi ngủ.'),
    ('daffb67a-0ab8-5826-b178-6351cbeab284', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'bedroom', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbɛdɹʊm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bedroom-us.mp3', 'A room in a house where a bed is kept for sleeping.', 'Please don''t enter my bedroom without knocking.', 'Home & Living', 'phòng ngủ', 'Một căn phòng trong nhà nơi đặt giường để ngủ.', 'Làm ơn đừng vào phòng ngủ của tôi mà không gõ cửa.'),
    ('82edf052-c50d-52cf-9391-8ab259cfae1c', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'building', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbɪl.dɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/building-uk.mp3', 'The act or process by which something is built; construction.', 'The building of the bridge will be completed in a couple of weeks.', 'Home & Living', 'tòa nhà', 'Hành động hoặc quá trình mà thứ gì đó được xây dựng; công trình xây dựng.', 'Việc xây dựng cây cầu sẽ hoàn thành trong vài tuần nữa.'),
    ('b351b5d8-709a-5a07-96d9-c58f11e50c09', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'chair', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/t͡ʃɛə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chair-uk.mp3', 'An item of furniture used to sit on or in, comprising a seat, legs, back, and sometimes arm rests, for use by one person. Compare stool, couch, sofa, settee, loveseat and bench.', 'All I need to weather a snowstorm is hot coffee, a warm fire, a good book and a comfortable chair.', 'Home & Living', 'ghế', 'Một món đồ nội thất dùng để ngồi lên hoặc ngồi trong, bao gồm chỗ ngồi, chân, lưng và đôi khi có tay vịn, dành cho một người sử dụng. So sánh với ghế đẩu, đi văng, sofa, ghế dài và ghế băng.', 'Tất cả những gì tôi cần để vượt qua một trận bão tuyết là cà phê nóng, lửa ấm, một cuốn sách hay và một chiếc ghế thoải mái.'),
    ('db993e4f-1a7a-5022-9b71-6d915b449f1b', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'clean', 'A1', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/kleːn/', 'audio/clean.mp3', 'Removal of dirt.', 'This place needs a clean.', 'Home & Living', 'sạch sẽ, lau chùi', 'Sự loại bỏ bụi bẩn.', 'Nơi này cần được dọn dẹp.'),
    ('640410fb-3955-50e8-ae2d-89589bb400e2', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'clock', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/klɒk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/clock-uk.mp3', 'An instrument used to measure or keep track of time; a non-portable timepiece.', 'This car has over 300,000 miles on the clock.', 'Home & Living', 'đồng hồ', 'Một dụng cụ dùng để đo hoặc theo dõi thời gian; một đồng hồ không di động.', 'Chiếc xe này đã chạy hơn 300.000 dặm trên đồng hồ đo.'),
    ('0a6d8f4b-1b81-5118-93c4-64599994b566', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'cup', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/kʌp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cup-uk.mp3', 'A concave vessel for drinking from, usually made of opaque material (as opposed to a glass) and with a handle.', 'Pour the tea into the cup.', 'Home & Living', 'cái tách', 'Một vật đựng lõm để uống, thường làm bằng chất liệu mờ đục (trái ngược với thủy tinh) và có tay cầm.', 'Đổ trà vào tách.'),
    ('a1fb35d2-386f-5df8-9676-e7c89575efbe', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'cut', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/kʌt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cut-au.mp3', 'The act of cutting.', 'He made a fine cut with his sword.', 'Home & Living', 'cắt', 'Hành động cắt.', 'Anh ấy thực hiện một nhát cắt tốt bằng thanh kiếm của mình.'),
    ('c45399ae-8a2e-526c-b942-e96093d9be01', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'desk', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/dɛsk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/desk-us.mp3', 'A table, frame, or case, in past centuries usually with a sloping top but now usually with a flat top, for the use of writers and readers. It often has a drawer or repository underneath.', 'city desk', 'Home & Living', 'bàn làm việc', 'Một cái bàn, khung, hoặc hộp, trong các thế kỷ trước thường có mặt trên nghiêng nhưng bây giờ thường có mặt trên phẳng, cho việc sử dụng của người viết và người đọc. Nó thường có ngăn kéo hoặc kho chứa bên dưới.', 'bàn thành phố'),
    ('7c53192a-03e7-5ca4-b167-2485523e6bbb', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'door', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/dɔː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/door-uk.mp3', 'A portal of entry into a building, room, or vehicle, consisting of a rigid plane movable on a hinge. Doors are frequently made of wood or metal. May have a handle to help open and close, a latch to hold the door closed and a lock that ensures the door cannot be opened without the key.', 'I knocked on the vice president''s door', 'Home & Living', 'cửa', 'Lối vào một tòa nhà, phòng hoặc phương tiện, bao gồm một mặt phẳng cứng có thể di chuyển trên bản lề. Cửa thường được làm bằng gỗ hoặc kim loại. Có thể có tay cầm để giúp mở và đóng, chốt để giữ...', 'Tôi đã gõ cửa phó chủ tịch'),
    ('8771a030-bdef-5e84-ad67-c42077afd34b', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'downstairs', 'A1', '["adv", "adj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/daʊnˈstɛəz/', 'audio/downstairs.mp3', 'The lower floor of a house, at ground level.', 'The wind lifted up her skirt and I caught a glimpse of her downstairs.', 'Home & Living', 'tầng dưới', 'Tầng thấp hơn của một ngôi nhà, ở mặt đất.', 'Gió thổi tung váy cô ấy lên và tôi đã lén nhìn thấy phần dưới của cô ấy.'),
    ('f4816c8d-a611-509e-a59e-e9a6392e7056', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'farm', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/fɑːɹm/', 'audio/farm.mp3', 'A place where agricultural and similar activities take place, especially the growing of crops or the raising of livestock.', 'antenna farm', 'Home & Living', 'nông trại', 'Một nơi diễn ra các hoạt động nông nghiệp và tương tự, đặc biệt là trồng trọt hoặc chăn nuôi.', 'trang trại ăng-ten'),
    ('7e68dea1-0cfb-55ff-ab1e-04cc15063996', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'fill', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/fɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fill-us.mp3', 'To occupy fully, to take up all of.', 'the bucket filled with rain; the sails fill with wind', 'Home & Living', 'làm đầy', 'Chiếm đầy, chiếm hết tất cả.', 'cái xô đầy nước mưa; những cánh buồm căng đầy gió'),
    ('73a2b2fb-a297-5df9-98f5-f6ee8423d8c1', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'flat', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/flæt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/flat-au.mp3', 'An area of level ground.', 'She liked to walk in her flats more than in her high heels.', 'Home & Living', 'căn hộ', 'Một khu vực đất bằng phẳng.', 'Cô ấy thích đi bộ bằng giày đế bằng hơn là giày cao gót.'),
    ('d8bb437d-88d0-5c97-8020-d61cd442a12c', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'floor', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/flɔː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/floor-uk.mp3', 'The interior bottom or surface of a house or building; the supporting surface of a room.', 'The room has a wooden floor.', 'Home & Living', 'sàn nhà', 'Mặt đáy hoặc bề mặt bên trong của một ngôi nhà hoặc tòa nhà; bề mặt chịu lực của một căn phòng.', 'Căn phòng có sàn gỗ.'),
    ('92131a1b-c519-54c8-a67e-e29c6d0886a7', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'garden', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɡɑːdn̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/garden-uk.mp3', 'An outdoor area containing one or more types of plants, usually plants grown for food or ornamental purposes.', 'a vegetable garden a flower garden', 'Home & Living', 'khu vườn', 'Một khu vực ngoài trời chứa một hoặc nhiều loại cây, thường là cây trồng để lấy thực phẩm hoặc mục đích trang trí.', 'một khu vườn rau một vườn hoa'),
    ('ccdabb89-ca8f-5f81-8c79-6cec5c51c360', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'glass', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɡlɑːs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/glass-uk.mp3', 'To apply fibreglass to.', 'to fibreglass the hull of a fishing-boat', 'Home & Living', 'thủy tinh', 'Áp dụng sợi thủy tinh vào.', 'phủ sợi thủy tinh lên thân tàu của một chiếc thuyền đánh cá'),
    ('ec529b74-a11c-528e-bb5c-750c1c0299c0', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'home', 'A1', '["n", "adv", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/(h)əʊm/', 'audio/home.mp3', 'A dwelling.', 'the home of the pine', 'Home & Living', 'nhà', 'Một nơi ở.', 'ngôi nhà của cây thông'),
    ('504e390e-a86f-5b6f-bfa9-d446f4487f90', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'house', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/hʌʊs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/house-1-ca.mp3', 'A structure built or serving as an abode of human beings.', 'This is my house and my family''s ancestral home.', 'Home & Living', 'ngôi nhà', 'Một công trình được xây dựng hoặc dùng làm nơi ở của con người.', 'Đây là nhà của tôi và là nhà tổ tiên của gia đình tôi.'),
    ('59eed5ba-a794-5b7b-a216-9ab8c10b14aa', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'let', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/lɛt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/let-us.mp3', 'The allowing of possession of a property etc. in exchange for rent.', 'After he knocked for hours, I decided to let him come in.', 'Home & Living', 'cho phép, cho thuê', 'Việc cho phép sở hữu một tài sản, v.v. để đổi lấy tiền thuê.', 'Sau khi anh ta gõ cửa hàng giờ, tôi quyết định để anh ta vào.'),
    ('76f614f8-5cae-5b10-9500-7f366b609cc0', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'neighbour', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈneɪbə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/neighbour-uk.mp3', 'A person living on adjacent or nearby land; a person situated adjacently or nearby; anything (of the same type of thing as the subject) in an adjacent or nearby position.', 'My neighbour has two noisy cats.', 'Home & Living', 'hàng xóm', 'Người sống trên đất liền kề hoặc gần đó; người ở vị trí liền kề hoặc gần đó; bất cứ thứ gì (cùng loại với chủ thể) ở vị trí liền kề hoặc gần đó.', 'Hàng xóm của tôi có hai con mèo ồn ào.'),
    ('a152b6b4-8a8e-57b9-ae37-d039e1d814c7', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'open', 'A1', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ˈəʊ.pən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/open-uk.mp3', 'Not closed', 'an open hand; an open flower', 'Home & Living', 'mở', 'Không đóng', 'một bàn tay mở; một bông hoa nở'),
    ('a7026000-e978-5554-8a94-31278526c9c3', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'pen', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/pɛn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pen.mp3', 'An enclosure (enclosed area) used to contain domesticated animals, especially sheep or cattle.', 'There are two steers in the third pen.', 'Home & Living', 'cái bút, chuồng', 'Một khu vực kín (khu vực có rào) dùng để nhốt động vật nuôi, đặc biệt là cừu hoặc gia súc.', 'Có hai con bò đực trong chuồng thứ ba.'),
    ('bd856005-284c-5b3e-b6c2-ee5719bd9f4b', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'place', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/pleɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/place-uk.mp3', '(physical) An area; somewhere within an area.', 'I''m in a strange place at the moment.', 'Home & Living', 'địa điểm', '(vật lý) Một khu vực; đâu đó trong một khu vực.', 'Tôi đang ở một nơi kỳ lạ vào lúc này.'),
    ('057abb9d-6fd7-5c26-8ddd-487b00fcc16d', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'post', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/pəʊst/', 'audio/post.mp3', 'A long dowel or plank protruding from the ground; a fencepost; a lightpost.', 'ram a post into the ground', 'Home & Living', 'cột', 'Một thanh trụ dài hoặc tấm ván nhô lên từ mặt đất; cột hàng rào; cột đèn.', 'đóng một cái cột xuống đất'),
    ('f46167e2-4ff7-5b0c-928d-5237eae76c49', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'room', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɹuːm/', 'audio/room.mp3', 'Opportunity or scope (to do something).', 'Go to your room!', 'Home & Living', 'căn phòng', 'Cơ hội hoặc phạm vi (để làm điều gì đó).', 'Về phòng của con đi!'),
    ('d5acb360-1ace-57ea-a9df-52255b847bf5', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'table', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈteɪbəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/table-uk.mp3', 'Furniture with a top surface to accommodate a variety of uses.', 'to table fines', 'Home & Living', 'cái bàn', 'Đồ nội thất có bề mặt phía trên để phục vụ nhiều mục đích sử dụng khác nhau.', 'đưa ra mức phí'),
    ('cc31a2e2-97e1-5417-9ee3-fd150e25b622', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'toilet', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈtɔɪ.lət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/toilet-uk.mp3', 'A covering of linen, silk, or tapestry, spread over a dressing table in a chamber or dressing room.', 'Sorry, I was in the toilet.', 'Home & Living', 'nhà vệ sinh', 'Một tấm phủ bằng vải lanh, lụa, hoặc thảm, trải trên bàn trang điểm trong phòng ngủ hoặc phòng thay đồ.', 'Xin lỗi, tôi đang trong nhà vệ sinh.'),
    ('a6f838f1-80f2-5b33-9587-bbb023092c7b', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'town', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/taʊn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/town-uk.mp3', 'A settlement; an area with residential districts, shops and amenities, and its own local government; especially one larger than a village and smaller than a city.', 'This town is really dangerous because these youngsters have Beretta handguns.', 'Home & Living', 'thị trấn', 'Một khu định cư; khu vực có khu dân cư, cửa hàng và tiện ích, và chính quyền địa phương riêng; đặc biệt là nơi lớn hơn làng và nhỏ hơn thành phố.', 'Thị trấn này thực sự nguy hiểm vì những thanh niên này có súng ngắn Beretta.'),
    ('06d45be7-56d8-5680-9a9a-3e11e223ef34', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'umbrella', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ʌmˈbɹɛlə/', 'audio/umbrella.mp3', 'Cloth-covered frame used for protection against rain or sun.', 'Quick, grab that umbrella before you get rained on!', 'Home & Living', 'cái ô/dù', 'Khung phủ vải dùng để bảo vệ khỏi mưa hoặc nắng.', 'Nhanh lên, lấy cái ô đó trước khi bị mưa ướt!'),
    ('2469a776-3373-58aa-92f3-5d3db1a083e2', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'upstairs', 'A1', '["adv", "adj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ˈʌpˌstɛəz/', 'audio/upstairs.mp3', 'An upper storey.', 'They can sleep in the upstairs bedroom.', 'Home & Living', 'tầng trên', 'Một tầng trên.', 'Họ có thể ngủ ở phòng ngủ tầng trên.'),
    ('e54cb0b1-0f62-5f35-866a-1bfc63294ca6', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'wall', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/wɔːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wall-uk.mp3', 'A rampart of earth, stones etc. built up for defensive purposes.', 'The town wall was surrounded by a moat.', 'Home & Living', 'bức tường', 'Một bức tường thành bằng đất, đá, v.v. được xây dựng cho mục đích phòng thủ.', 'Tường thành của thị trấn được bao quanh bởi một con hào.'),
    ('5700efce-bb92-5eaf-8cac-38db0771f030', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'wash', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/wɑʃ/', 'audio/wash.mp3', 'The process or an instance of washing or being washed by water or other liquid.', 'I''m going to have a quick wash before coming to bed.', 'Home & Living', 'giặt rửa', 'Quá trình hoặc một lần giặt hoặc được giặt bằng nước hoặc chất lỏng khác.', 'Tôi sẽ đi rửa qua một chút trước khi lên giường.'),
    ('2bdbaa8c-1845-567a-8bed-add07ed7a58d', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'window', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈwɪndəʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/window-uk.mp3', 'The inedible parts of a grain-producing plant.', 'To separate out the chaff, early cultures tossed baskets of grain into the air and let the wind blow away the lighter chaff.', 'Home & Living', 'cửa sổ', 'Các phần không ăn được của một cây sản xuất hạt.', 'Để tách trấu ra, các nền văn hóa ban đầu ném những giỏ hạt lên không trung và để gió thổi bay lớp trấu nhẹ hơn.'),
    ('be4d5518-63a0-58eb-8900-c22f89ab58bd', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'outside', 'A1', '["adv", "prep", "n", "adj"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "prep", "level": "A1"}, {"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}]'::jsonb, NULL, 'audio/outside.mp3', 'The part of something that faces out; the outer surface.', 'He''s repainting the outside of his house.', 'Home & Living', 'bên ngoài', 'Phần của một thứ hướng ra ngoài; bề mặt bên ngoài.', 'Anh ấy đang sơn lại mặt ngoài ngôi nhà của mình.'),
    ('d9d3bb5e-fdd5-5d48-9370-f6604567e44c', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'apartment', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/əˈpɑːt.mənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/apartment-uk.mp3', 'A complete domicile occupying only part of a building, especially one for rent; a flat.', NULL, 'Home & Living', 'căn hộ', 'Một nơi cư trú hoàn chỉnh chỉ chiếm một phần của tòa nhà, đặc biệt là để cho thuê; một căn hộ.', NULL),
    ('ea2fa7da-be24-5a43-858f-4a101c50dec9', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'box', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɒks/', 'audio/box.mp3', 'Senses relating to a three-dimensional object or space.', NULL, 'Home & Living', 'hộp', 'Các nghĩa liên quan đến một vật thể hoặc không gian ba chiều.', NULL),
    ('796680f1-7b86-513a-842b-634f5f7a8795', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'cat', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/kat/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cat-uk.mp3', 'An animal of the family Felidae:', NULL, 'Home & Living', 'mèo', 'Một động vật thuộc họ Felidae:', NULL),
    ('bfc97d41-21ee-5729-b996-b98236bcdfc9', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'kitchen', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkɪt͡ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/kitchen-uk.mp3', 'A room or area for preparing food.', NULL, 'Home & Living', 'nhà bếp', 'Một căn phòng hoặc khu vực để chuẩn bị thức ăn.', NULL),
    ('547571dc-4321-5a7c-b93a-d9b308bb3da6', 'a15741e5-39da-5b08-a051-ecf9146cb37d', 'live1', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, NULL, 'audio/live1.mp3', NULL, NULL, 'Home & Living', 'sống', NULL, NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

