INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('c2f03b7f-423f-5349-a3c0-50033c12f99c', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'arm', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɑːm/', 'audio/arm.mp3', 'The portion of the upper human appendage, from the shoulder to the wrist and sometimes including the hand.', 'She stood with her right arm extended and her palm forward to indicate “Stop!”', 'Health & Body', 'cánh tay', 'Phần của chi trên của con người, từ vai đến cổ tay và đôi khi bao gồm cả bàn tay.', 'Cô ấy đứng với cánh tay phải duỗi ra và lòng bàn tay hướng về phía trước để ra hiệu ''Dừng lại!'''),
    ('6a8723a5-854f-542b-a5cc-b082e2b4c562', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'back', 'A1', '["n", "adv", "adj", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/bæk/', 'audio/back.mp3', 'The rear of the body, especially the part between the neck and the end of the spine and opposite the chest and belly.', 'Could you please scratch my back?', 'Health & Body', 'lưng', 'Phía sau của cơ thể, đặc biệt là phần giữa cổ và cuối cột sống và đối diện với ngực và bụng.', 'Bạn có thể gãi lưng giúp tôi được không?'),
    ('33a14bc5-2b93-5910-8f83-217cd9c688ab', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'body', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbɒdi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/body-uk.mp3', 'Physical frame.', 'a nonpareil face on an agate body', 'Health & Body', 'cơ thể', 'Khung hình thể chất.', 'một khuôn mặt không ai sánh bằng trên một thân thể mã não'),
    ('ed5281dd-9eda-58b0-8dc2-3acf297bc4e2', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'dangerous', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈdeɪnd͡ʒ(ə)ɹəs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dangerous-uk.mp3', 'Full of danger.', 'Railway crossings without gates are highly dangerous.', 'Health & Body', 'nguy hiểm', 'Đầy nguy hiểm.', 'Các đoạn đường ngang qua đường sắt không có rào chắn cực kỳ nguy hiểm.'),
    ('d06fac05-d634-5591-a9f4-9f78e455ac3b', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'die', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/daɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/die-us.mp3', 'To stop living; to become dead; to undergo death.', 'He died a hero''s death.', 'Health & Body', 'chết', 'Ngừng sống; trở nên đã chết; trải qua cái chết.', 'Anh ấy chết một cái chết của anh hùng.'),
    ('29b3be7a-904a-5aa8-9569-95aee84298fb', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'diet', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈdaɪət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/diet-us.mp3', 'The food and beverage a person or animal consumes.', 'The diet of the Giant Panda consists mainly of bamboo.', 'Health & Body', 'chế độ ăn', 'Thức ăn và đồ uống mà một người hoặc động vật tiêu thụ.', 'Chế độ ăn của Gấu Trúc Khổng Lồ chủ yếu gồm tre trúc.'),
    ('c42d7166-463d-5622-83b9-c4810a7c1f88', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'doctor', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈdɒktə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/doctor-uk.mp3', 'A physician; a member of the medical profession; one who is trained and licensed to heal the sick or injured. The final examination and qualification may award a doctor degree in which case the post-nominal letters are D.O., DPM, M.D., DMD, DDS, in the US or MBBS in the UK.', 'If you still feel unwell tomorrow, see your doctor.', 'Health & Body', 'bác sĩ', 'Một bác sĩ y khoa; một thành viên của ngành y; người được đào tạo và cấp phép để chữa bệnh cho người bệnh hoặc bị thương. Kỳ thi cuối cùng và bằng cấp có thể trao bằng tiến sĩ, trong trường hợp đó, danh hiệu hậu tố...', 'Nếu ngày mai bạn vẫn cảm thấy không khỏe, hãy đi gặp bác sĩ của bạn.'),
    ('39dce759-6c7e-528c-9521-0e41c8fd2c37', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'ear', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɪə̯/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ear-uk.mp3', 'The organ of hearing, consisting of the pinna, auditory canal, eardrum, malleus, incus, stapes and cochlea.', 'a good ear for music', 'Health & Body', 'tai', 'Cơ quan thính giác, bao gồm vành tai, ống tai, màng nhĩ, xương búa, xương đe, xương bàn đạp và ốc tai.', 'có tai nghe nhạc tốt'),
    ('e98624cf-1c77-544e-baaf-c379d3f583c5', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'eye', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/aɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/eye-us.mp3', 'An organ through which animals see (perceive surroundings via light).', 'Bright lights really hurt my eyes.', 'Health & Body', 'mắt', 'Một cơ quan mà qua đó động vật nhìn thấy (nhận thức môi trường xung quanh qua ánh sáng).', 'Ánh sáng mạnh thực sự làm đau mắt tôi.'),
    ('30603d17-133a-53eb-9923-0bca8cceabf6', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'face', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/feɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/face-au.mp3', 'The front part of the head of a human or other animal, featuring the eyes, nose and mouth, and the surrounding area.', 'That girl has a pretty face.', 'Health & Body', 'khuôn mặt', 'Phần trước của đầu người hoặc động vật khác, có đặc điểm là mắt, mũi và miệng, và khu vực xung quanh.', 'Cô gái đó có một khuôn mặt xinh đẹp.'),
    ('739a4fd1-5e32-595f-9dd7-f1f4957a79fd', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'fat', 'A1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/fæt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fat-us.mp3', 'A specialized animal tissue with a high oil content, used for long-term storage of energy.', 'We need to trim the fat in this company', 'Health & Body', 'béo, mỡ', 'Một loại mô động vật chuyên biệt có hàm lượng dầu cao, được sử dụng để lưu trữ năng lượng lâu dài.', 'Chúng ta cần cắt giảm phần mỡ thừa trong công ty này'),
    ('c90da38d-2226-5ecb-b663-fe8510712ac0', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'foot', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '[fʊt̚]', 'audio/foot.mp3', 'A biological structure found in many animals that is used for locomotion and that is frequently a separate organ at the terminal part of the leg.', 'A spider has eight feet.', 'Health & Body', 'bàn chân', 'Một cấu trúc sinh học được tìm thấy ở nhiều loài động vật được sử dụng cho việc di chuyển và thường là một cơ quan riêng biệt ở phần cuối của chân.', 'Một con nhện có tám chân.'),
    ('0b95e1dd-b884-5555-920d-23e4b7607b63', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'hand', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/hænd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hand-uk.mp3', 'The part of the forelimb below the forearm or wrist in a human, and the corresponding part in many other animals.', 'Her hands are really strong.', 'Health & Body', 'bàn tay', 'Phần chi trước dưới cẳng tay hoặc cổ tay ở người, và phần tương ứng ở nhiều loài động vật khác.', 'Đôi tay của cô ấy thực sự khỏe.'),
    ('f415720b-585b-5094-8b68-aabe42e77c5c', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'head', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/hɛd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/head-uk.mp3', 'The part of the body of an animal or human which contains the brain, mouth and main sense organs.', 'Be careful when you pet that dog on the head; it may bite.', 'Health & Body', 'đầu', 'Phần cơ thể của động vật hoặc con người chứa não, miệng và các cơ quan cảm giác chính.', 'Hãy cẩn thận khi bạn vuốt ve con chó đó trên đầu; nó có thể cắn.'),
    ('cc3321c7-3165-524d-aafe-0e9808acd0b2', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'health', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/hɛlθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/health-1-uk.mp3', 'The state of being free from physical or psychological disease, illness, or malfunction; wellness.', 'Her mental health is really affected by stressful environments.', 'Health & Body', 'sức khỏe', 'Trạng thái không bị bệnh tật, ốm đau hoặc rối loạn về thể chất hoặc tâm lý; sự khỏe mạnh.', 'Sức khỏe tinh thần của cô ấy thực sự bị ảnh hưởng bởi môi trường căng thẳng.'),
    ('ddf22521-8a0f-5bfa-bd84-77aaf980bb31', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'healthy', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈhɛl.θi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/healthy-us.mp3', 'Enjoying health and vigor of body, mind, or spirit: well.', 'He was father to three healthy kids.', 'Health & Body', 'khỏe mạnh', 'Tận hưởng sức khỏe và sức sống của cơ thể, tâm trí, hoặc tinh thần: khỏe mạnh.', 'Ông ấy là cha của ba đứa trẻ khỏe mạnh.'),
    ('13da6e1d-bffe-5539-bc64-3386301c7a99', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'hear', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/hɪə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hear-uk.mp3', '(stative) To perceive sounds through the ear.', 'I was deaf, and now I can hear.', 'Health & Body', 'nghe', '(trạng thái) Nhận thức âm thanh qua tai.', 'Tôi đã bị điếc, và bây giờ tôi có thể nghe.'),
    ('5961bc9e-ae98-5d96-bf82-b473c3752b83', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'hungry', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈhʌŋ.ɡɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hungry-us.mp3', 'Affected by hunger; desiring of food; having a physical need for food.', 'My kids go to bed hungry every night because I haven''t got any money.', 'Health & Body', 'đói', 'Bị ảnh hưởng bởi cơn đói; khao khát thức ăn; có nhu cầu thể chất về thức ăn.', 'Những đứa trẻ của tôi đi ngủ mỗi đêm với cái bụng đói vì tôi không có tiền.'),
    ('ea7468b9-075d-5ea1-b9ed-96e6584a149d', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'leg', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/leɪɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/leg-1-au.mp3', 'A limb or appendage that an animal uses for support or locomotion.', '{{ux|en|Insects have six legs.}', 'Health & Body', 'chân', 'Một chi hoặc phần phụ mà động vật sử dụng để nâng đỡ hoặc di chuyển.', 'Côn trùng có sáu chân.'),
    ('662cbfbd-1a49-58e8-b5d4-5449cb3bc2e8', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'life', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/laɪf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/life-uk.mp3', 'The state of organisms preceding their death, characterized by biological processes such as metabolism and reproduction and distinguishing them from inanimate objects; the state of being alive and living.', 'Having experienced both, the vampire decided that he preferred (un)death to life. He gave up on life.', 'Health & Body', 'cuộc sống, sự sống', 'Trạng thái của các sinh vật trước khi chết, được đặc trưng bởi các quá trình sinh học như trao đổi chất và sinh sản và phân biệt chúng với các vật thể vô tri; trạng thái đang sống và sinh tồn', 'Đã trải qua cả hai, ma cà rồng quyết định rằng hắn thích cái chết (không sống) hơn là sự sống. Anh ấy từ bỏ cuộc sống.'),
    ('53269272-a3ba-55e0-bb62-d8f50e7927fc', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'mouth', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/mʌʊθ/', 'audio/mouth.mp3', 'The opening of a creature through which food is ingested.', '"Open your mouth and say ''aah''," directed the doctor.', 'Health & Body', 'miệng', 'Đường mở của một sinh vật qua đó thức ăn được đưa vào.', '"Mở miệng ra và nói ''a'' đi," bác sĩ chỉ dẫn.'),
    ('112bf701-5ea9-5918-9c76-34157644c8ba', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'nose', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/nəʊz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/nose-uk.mp3', 'A protuberance on the face housing the nostrils, which are used to breathe or smell.', 'She has a cold in the nose.', 'Health & Body', 'mũi', 'Phần nhô ra trên khuôn mặt chứa lỗ mũi, được dùng để thở hoặc ngửi.', 'Cô ấy bị cảm lạnh ở mũi.'),
    ('6a31de07-c699-5271-a23e-e2a29770606b', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'nurse', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/nɜːs/', 'audio/nurse.mp3', 'A wet nurse.', 'They hired a nurse to care for their young boy.', 'Health & Body', 'y tá', 'Một vú em.', 'Họ thuê một y tá để chăm sóc cậu con trai nhỏ của họ.'),
    ('d883a5af-3121-5a57-b836-709d014217bf', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'sick', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/sɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sick-uk.mp3', 'Sick people in general as a group.', 'We have to cure the sick.', 'Health & Body', 'ốm', 'Người ốm nói chung như một nhóm.', 'Chúng ta phải chữa trị cho người bệnh.'),
    ('78794a3c-33d4-5751-98e9-9e7f2dab399d', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'sleep', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/sliːp/', 'audio/sleep.mp3', 'To rest in a state of reduced consciousness.', 'You should sleep 8 hours a day.', 'Health & Body', 'ngủ/giấc ngủ', 'Nghỉ ngơi trong trạng thái ý thức bị giảm.', 'Bạn nên ngủ 8 tiếng mỗi ngày.'),
    ('ed3f686d-309e-5722-aafa-dc6cdf653442', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'sound', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/saʊnd/', 'audio/sound.mp3', 'Healthy.', 'He was safe and sound.', 'Health & Body', 'âm thanh', 'Khỏe mạnh.', 'Anh ấy đã an toàn và khỏe mạnh.'),
    ('da636977-2ea5-50e3-b98a-c5fe063e0cd5', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'strong', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/stɹɑŋ/', 'audio/strong.mp3', 'Capable of producing great physical force.', 'a big strong man; Jake was tall and strong', 'Health & Body', 'mạnh mẽ', 'Có khả năng tạo ra lực vật lý lớn.', 'một người đàn ông to lớn mạnh mẽ; Jake cao và khỏe'),
    ('cedd7af8-1078-5348-964e-f78ac36c9ff0', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'thirsty', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈθɜː(ɹ)st.i/', 'https://api.dictionaryapi.dev/media/pronunciations/en/thirsty-us.mp3', 'Needing to drink.', 'After all that work I am really thirsty.', 'Health & Body', 'khát', 'Cần uống nước.', 'Sau tất cả công việc đó tôi thực sự khát.'),
    ('af67cb88-8513-5932-9e6c-a25204026492', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'tired', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/taɪəd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tired-uk.mp3', 'To become sleepy or weary.', 'I tire of this book.', 'Health & Body', 'mệt mỏi', 'Trở nên buồn ngủ hoặc mệt mỏi.', 'Tôi thấy chán cuốn sách này.'),
    ('f332cdcf-2ca5-5d84-a57d-9724ef42c4c6', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'tooth', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/tuːθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tooth-uk.mp3', 'A hard, calcareous structure present in the mouth of many vertebrate animals, generally used for eating.', 'I have a sweet tooth: I love sugary treats.', 'Health & Body', 'răng', 'Một cấu trúc cứng, bằng canxi có trong miệng của nhiều loài động vật có xương sống, thường được dùng để ăn.', 'Tôi có sở thích ăn ngọt: Tôi thích các món ngọt.'),
    ('3296cc0a-dd93-56d7-9e4b-f62eddb8ba82', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'well', 'A1', '["adv", "adj", "exclam"]'::jsonb, '[{"pos": "adv", "level": "A1"}, {"pos": "adj", "level": "A1"}, {"pos": "exclam", "level": "A1"}]'::jsonb, '/wɛl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/well-uk.mp3', 'In good health.', 'I had been sick, but now I''m well.', 'Health & Body', 'khỏe', 'Có sức khỏe tốt.', 'Tôi đã bị ốm, nhưng giờ tôi khỏe rồi.'),
    ('193e4454-abcf-5d85-9d34-1d48a7197fa8', 'e16245ce-2455-5e8c-94ca-bf177644445f', 'hospital', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈhɒs.pɪ.tl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hospital-uk.mp3', 'A large medical facility, usually in a building with multiple floors, where seriously ill or injured patients are given extensive medical and/or surgical treatment.', NULL, 'Health & Body', 'bệnh viện', NULL, NULL)
