    ('32dc54fb-7c2d-502c-a315-0a9f9c582683', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'left', 'A1', '["adj", "adv", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/lɛft/', 'https://api.dictionaryapi.dev/media/pronunciations/en/left-1-uk.mp3', 'The left side or direction.', 'The political left is holding too much power.', 'Appearance & Description', 'bên trái', 'Phía hoặc hướng bên trái.', 'Cánh tả chính trị đang nắm quá nhiều quyền lực.'),
    ('306fff0b-fa5b-589a-bbe3-5c69dda894c6', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'new', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/njʉː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/new-au.mp3', 'Things that are new.', 'Out with the old, in with the new.', 'Appearance & Description', 'mới', 'Những thứ mới.', 'Vứt cái cũ đi, đón cái mới vào.'),
    ('4f9271e2-04c5-5b19-b12f-838edca7dbf0', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'nice', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/naɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/nice-us.mp3', 'Niceness.', 'What is a nice person like you doing in a place like this?', 'Appearance & Description', 'tốt đẹp, dễ chịu', 'Sự tốt đẹp, dễ chịu.', 'Một người tốt như bạn đang làm gì ở một nơi như thế này?'),
    ('9b3ffee9-54e9-5312-b70e-64d759947567', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'old', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈɒʊld/', 'https://api.dictionaryapi.dev/media/pronunciations/en/old-uk.mp3', '(with the, invariable plural only) People who are old; old beings; the older generation, taken as a group.', 'A civilised society should always look after the old in the community.', 'Appearance & Description', 'cũ, già', '(với ''the'', dạng số nhiều không đổi) Những người già; những sinh vật già; thế hệ lớn tuổi, được xem như một nhóm.', 'Một xã hội văn minh nên luôn chăm sóc người già trong cộng đồng.'),
    ('f452db01-e812-5cb3-a653-127bdaa9e52e', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'opposite', 'A1', '["adj", "adv", "prep", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}, {"pos": "prep", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ˈɒpəsɪt/', 'audio/opposite.mp3', 'Something opposite or contrary to something else.', '"Up" is the opposite of "down".', 'Appearance & Description', 'đối diện, trái ngược', 'Một thứ đối lập hoặc trái ngược với thứ khác.', '"Lên" là trái ngược với "xuống".'),
    ('ccabd25e-4edc-5b2a-afdf-7c429729ffee', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'pair', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/pɛə(ɹ)/', 'audio/pair.mp3', 'Two similar or identical things taken together; often followed by of.', 'I couldn''t decide which of the pair of designer shirts I preferred, so I bought the pair.', 'Appearance & Description', 'đôi, cặp', 'Hai thứ tương tự hoặc giống hệt nhau được ghép lại với nhau; thường theo sau là ''of''.', 'Tôi không thể quyết định nên chọn chiếc áo sơ mi thiết kế nào trong hai chiếc, nên tôi mua cả đôi.'),
    ('350322d8-7bd0-54e6-9a6f-6b4dabcebd8a', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'pretty', 'A1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/ˈpɹɪti/', 'audio/pretty.mp3', 'A pretty person; a term of address to a pretty person.', 'We''ll stop at the knife store and look at the sharp pretties.', 'Appearance & Description', 'xinh đẹp', 'Một người xinh đẹp; một cách xưng hô với một người xinh đẹp.', 'Chúng ta sẽ dừng ở cửa hàng dao và ngắm những món đồ sắc bén đẹp đẽ.'),
    ('a0ffde6c-3c5d-52d4-a9ce-1014ac497501', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'purple', 'A1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɜː(ɹ).pəl/', 'audio/purple.mp3', 'A colour/color that is a dark blend of red and blue; dark magenta.', 'to put on the imperial purple', 'Appearance & Description', 'màu tím', 'Một màu sắc là sự pha trộn đậm giữa đỏ và xanh dương; đỏ tươi đậm.', 'mặc áo choàng hoàng gia màu tím'),
    ('a72fdde3-badc-5e1c-b8de-761270473cee', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'quick', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/kwɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/quick-au.mp3', 'Raw or sensitive flesh, especially that underneath finger and toe nails.', 'He''s a quick runner.', 'Appearance & Description', 'nhanh', 'Thịt sống hoặc nhạy cảm, đặc biệt là phần ở dưới móng tay và móng chân.', 'Anh ấy là một người chạy nhanh.'),
    ('ac20cb7e-fa10-5fd1-8aaa-02b1229d6ed7', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'quiet', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈkwaɪ.ət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/quiet-us.mp3', 'The absence of sound; quietness.', 'There was a strange quiet in the normally very lively plaza.', 'Appearance & Description', 'yên tĩnh', 'Sự vắng bóng của âm thanh; sự yên tĩnh.', 'Có một sự yên tĩnh kỳ lạ ở quảng trường vốn thường rất nhộn nhịp.'),
    ('10f873bf-0d97-5264-9a13-509e3c378325', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'real', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ɹiːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/real-1-uk.mp3', 'A commodity; see realty.', 'This is real leather.', 'Appearance & Description', 'thật', 'Một mặt hàng; xem realty.', 'Đây là da thật.'),
    ('582d97d0-e1a7-5a27-8e82-3c2dc00765b9', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'red', 'A1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ɹɛd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/red-us.mp3', 'Any of a range of colours having the longest wavelengths, 670 nm, of the visible spectrum; a primary additive colour for transmitted light: the colour obtained by subtracting green and blue from white light using magenta and yellow filters; the colour of blood, ripe strawberries, etc.', 'The girl wore a red skirt.', 'Appearance & Description', 'màu đỏ', 'Bất kỳ màu nào trong dải màu có bước sóng dài nhất, 670 nm, của quang phổ nhìn thấy được; một màu cộng cơ bản cho ánh sáng truyền qua: màu thu được bằng cách trừ xanh lục và xanh lam từ trắng', 'Cô gái mặc một chiếc váy màu đỏ.'),
    ('1654c44a-50f2-506b-9b88-44b20f4f61cb', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'shirt', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ʃɜːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shirt-uk.mp3', 'An article of clothing that is worn on the upper part of the body, and often has sleeves, either long or short, that cover the arms.', 'It can take a while to learn how to iron a shirt properly.', 'Appearance & Description', 'áo sơ mi', 'Một loại quần áo được mặc ở phần trên của cơ thể, thường có tay áo dài hoặc ngắn để che cánh tay.', 'Có thể mất một lúc để học cách ủi áo sơ mi đúng cách.'),
    ('90017c9a-73bb-502f-bac5-4117ec868dfd', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'shoe', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ʃuː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shoe-us.mp3', 'A protective covering for the foot, with a bottom part composed of thick leather or plastic sole and often a thicker heel, and a softer upper part made of leather or synthetic material. Shoes generally do not extend above the ankle, as opposed to boots, which do.', 'Get your shoes on now, or you''ll be late for school.', 'Appearance & Description', 'giày', 'Vật bảo vệ che chân, với phần đế làm bằng da dày hoặc nhựa và thường có gót dày hơn, phần trên mềm hơn làm bằng da hoặc vật liệu tổng hợp.', 'Mang giày vào ngay đi, nếu không con sẽ muộn học.'),
    ('1f468dba-5bbb-5cdd-a6f2-6bb709805d4a', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'short', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ʃoːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/short-au.mp3', 'A short circuit.', '38 short suits fit me right off the rack.', 'Appearance & Description', 'ngắn', 'Một đoản mạch.', '38 bộ đồ ngắn vừa vặn với tôi ngay trên giá.'),
    ('074dc8d5-ee36-515f-a7da-f19a1975205f', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'skirt', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/skɜːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/skirt-uk.mp3', 'An article of clothing, usually worn by women and girls, that hangs from the waist and covers the lower part of the body.', 'The plain was skirted by rows of trees.', 'Appearance & Description', 'váy', 'Một loại quần áo, thường được phụ nữ và trẻ em gái mặc, buông từ thắt lưng và che phần dưới của cơ thể.', 'Đồng bằng được viền bởi những hàng cây.'),
    ('e123a3f6-1540-56be-9b6e-929b127fe872', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'slow', 'A1', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/sləʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/slow-uk.mp3', 'Someone who is slow; a sluggard.', 'a slow train; a slow computer', 'Appearance & Description', 'chậm', 'Một người nào đó chậm chạp; một kẻ lười biếng.', 'một chuyến tàu chậm; một máy tính chậm'),
    ('89988f6d-92f7-5fc2-abc1-53d98e491480', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'small', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/smoːl/', 'audio/small.mp3', 'Any part of something that is smaller or slimmer than the rest, now usually with anatomical reference to the back.', 'A small group.', 'Appearance & Description', 'nhỏ', 'Bất kỳ phần nào của một thứ nhỏ hơn hoặc mảnh hơn phần còn lại, thường đề cập đến giải phẫu phần lưng.', 'Một nhóm nhỏ.'),
    ('be58a544-0af5-52da-94de-75ad27597aa3', '6eaa1e4a-c521-58ae-a34d-f8e988082c40', 'tall', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/tɔːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tall-uk.mp3', '(possibly nonstandard) Someone or something that is tall.', 'Being tall is an advantage in basketball.', 'Appearance & Description', 'cao', '(có thể không chuẩn) Một người hoặc vật gì đó cao.', 'Cao là một lợi thế trong bóng rổ.')
