INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('e0131233-c21a-5414-b201-54fc7a946f5d', '473601da-3758-5b8f-84b4-daaf898d3a65', 'airport', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɛə.pɔːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/airport-uk.mp3', 'An airfield (an area designated for the takeoff and landing of aircraft), including one or more runways and (for commercial airports) one or more passenger terminals.', 'Because of this, and contrary to popular belief, British airports primarily act as giant wealth extractors, transporting our richest citizens out of the country as often as possible to take their money overseas. ― The Independent, Heathrow expansion to mainly benefit wealthy frequent fliers, research finds, 23 june 2018.', 'Travel & Transport', 'sân bay', 'Một sân bay (khu vực được chỉ định để cất cánh và hạ cánh của máy bay), bao gồm một hoặc nhiều đường băng và (đối với sân bay thương mại) một hoặc nhiều nhà ga hành khách.', 'Vì điều này, và trái với niềm tin phổ biến, các sân bay Anh chủ yếu đóng vai trò như những cỗ máy hút tài sản khổng lồ, vận chuyển những công dân giàu có nhất của chúng ta ra khỏi đất nước thường xuyên nhất có thể để mang tiền của họ đi.'),
    ('66e45b98-765f-538a-b30b-75b88b2dec83', '473601da-3758-5b8f-84b4-daaf898d3a65', 'arrive', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/əˈɹaɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/arrive-us.mp3', 'To reach; to get to a certain place.', 'He arrived home for two days.', 'Travel & Transport', 'đến nơi', 'Đi tới; đến được một nơi nhất định.', 'Anh ấy đã về đến nhà được hai ngày.'),
    ('bee8047c-6824-54cc-804d-8e817b61a066', '473601da-3758-5b8f-84b4-daaf898d3a65', 'bike', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '[bɐɪk]', 'audio/bike.mp3', 'A vehicle that has two wheels, one behind the other, a steering handle, and a saddle seat or seats and is usually propelled by the action of a rider’s feet upon pedals.', 'I biked so much yesterday that I''m very sore today.', 'Travel & Transport', 'xe đạp', 'Một phương tiện có hai bánh xe, một trước một sau, một tay lái, và một yên ngồi hoặc nhiều yên và thường được đẩy bằng động tác đạp bàn đạp của người lái.', 'Hôm qua tôi đạp xe nhiều đến mức hôm nay tôi rất đau.'),
    ('f3bf49ce-4588-53f3-abe3-896876033adc', '473601da-3758-5b8f-84b4-daaf898d3a65', 'boat', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bəʊt/', 'audio/boat.mp3', 'A craft used for transportation of goods, fishing, racing, recreational cruising, or military use on or in the water, propelled by oars or outboard motor or inboard motor or by wind.', 'a stone boat; a gravy boat', 'Travel & Transport', 'thuyền', 'Một phương tiện dùng để vận chuyển hàng hóa, đánh cá, đua, du ngoạn giải trí hoặc sử dụng quân sự trên hoặc trong nước, được đẩy bằng mái chèo hoặc động cơ ngoài hoặc động cơ trong hoặc bằng gió.', 'thuyền đá; thuyền sốt'),
    ('47051467-4170-5d3f-a5d3-d276ec30c697', '473601da-3758-5b8f-84b4-daaf898d3a65', 'bus', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɐs/', 'audio/bus.mp3', 'A motor vehicle for transporting large numbers of people along roads.', 'He bussed tables as the restaurant emptied out.', 'Travel & Transport', 'xe buýt', 'Một phương tiện cơ giới để vận chuyển số lượng lớn người dọc theo đường bộ.', 'Anh ấy dọn bàn khi nhà hàng vắng khách.'),
    ('5facdb72-1a4a-5185-8f6d-84912298bb6a', '473601da-3758-5b8f-84b4-daaf898d3a65', 'car', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/kɑː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/car-uk.mp3', 'A wheeled vehicle that moves independently, with at least three wheels, powered mechanically, steered by a driver and mostly for personal transportation.', 'She drove her car to the mall.', 'Travel & Transport', 'xe hơi', 'Một phương tiện có bánh xe di chuyển độc lập, với ít nhất ba bánh, được cung cấp năng lượng cơ học, điều khiển bởi tài xế và chủ yếu cho việc đi lại cá nhân.', 'Cô ấy lái xe hơi của mình đến trung tâm mua sắm.'),
    ('d5138183-7f97-5bdc-a24d-a6e8e7f25f4f', '473601da-3758-5b8f-84b4-daaf898d3a65', 'drive', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/dɹaɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/drive-au.mp3', 'Motivation to do or achieve something; ability coupled with ambition.', 'Crassus had wealth and wit, but Pompey had drive and Caesar as much again.', 'Travel & Transport', 'lái xe, động lực', 'Động lực để làm hoặc đạt được điều gì đó; khả năng đi kèm với tham vọng.', 'Crassus có sự giàu có và trí tuệ, nhưng Pompey có động lực và Caesar cũng vậy.'),
    ('199495a6-a8dd-5395-a849-e46cde81176b', '473601da-3758-5b8f-84b4-daaf898d3a65', 'fast', 'A1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/fɑːst/', 'audio/fast.mp3', 'A train that calls at only some stations it passes between its origin and destination, typically just the principal stations', 'That rope is dangerously loose. Make it fast!', 'Travel & Transport', 'nhanh, chắc', 'Một chuyến tàu chỉ dừng ở một số ga mà nó đi qua giữa điểm xuất phát và điểm đến, thường chỉ là các ga chính', 'Sợi dây đó lỏng nguy hiểm. Hãy buộc chắc nó lại!'),
    ('31731c9b-ca96-5424-a5c2-e1b942d72cc3', '473601da-3758-5b8f-84b4-daaf898d3a65', 'flight', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/flaɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/flight-au.mp3', 'The act of flying.', 'Most birds are capable of flight.', 'Travel & Transport', 'chuyến bay', 'Hành động bay.', 'Hầu hết các loài chim có khả năng bay.'),
    ('d2d2b58b-167f-5722-ab69-02bab71ca05a', '473601da-3758-5b8f-84b4-daaf898d3a65', 'journey', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈd͡ʒɜːni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/journey-uk.mp3', 'A set amount of travelling, seen as a single unit; a discrete trip, a voyage.', 'my journey of dealing with grief', 'Travel & Transport', 'hành trình', 'Một lượng di chuyển nhất định, được xem như một đơn vị duy nhất; một chuyến đi riêng biệt, một cuộc hành trình.', 'hành trình của tôi trong việc đối mặt với nỗi đau'),
    ('885e8434-0fbc-55a4-954a-6de02557452f', '473601da-3758-5b8f-84b4-daaf898d3a65', 'map', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/mæp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/map-uk.mp3', 'A visual representation of an area, whether real or imaginary.', 'I don''t want to play this map again!', 'Travel & Transport', 'bản đồ', 'Một biểu diễn trực quan của một khu vực, dù là thực hay tưởng tượng.', 'Tôi không muốn chơi bản đồ này nữa!'),
    ('212673fd-f3c8-54a2-b4d5-32e5c4f996e2', '473601da-3758-5b8f-84b4-daaf898d3a65', 'meet', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/miːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/meet-uk.mp3', 'A sports competition, especially for track and field (a track meet) or swimming (a swim meet).', 'OK, let''s arrange a meet with Tyler and ask him.', 'Travel & Transport', 'gặp gỡ', 'Một cuộc thi đấu thể thao, đặc biệt cho điền kinh (track meet) hoặc bơi lội (swim meet).', 'Được rồi, hãy sắp xếp một cuộc gặp với Tyler và hỏi anh ấy.'),
    ('e0264a40-b856-50ce-bffb-bfe2280d1639', '473601da-3758-5b8f-84b4-daaf898d3a65', 'passport', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɑːspɔːt/', 'audio/passport.mp3', 'An official document normally used for international journeys, which proves the identity and nationality of the person for whom it was issued.', 'You will have to bring your passport to prove who you are.', 'Travel & Transport', 'hộ chiếu', 'Một tài liệu chính thức thường được sử dụng cho các hành trình quốc tế, chứng minh danh tính và quốc tịch của người được cấp.', 'Bạn sẽ phải mang hộ chiếu để chứng minh bạn là ai.'),
    ('9fa95579-3e52-51d4-a8c6-4ec556c75905', '473601da-3758-5b8f-84b4-daaf898d3a65', 'return', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ɹɪˈtɜːn/', 'audio/return.mp3', 'The act of returning.', 'I expect the house to be spotless upon my return.', 'Travel & Transport', 'trở về', 'Hành động trở về.', 'Tôi mong ngôi nhà sẽ sạch sẽ khi tôi trở về.'),
    ('a72fccb2-6d51-5702-a80e-cdffee77a3e2', '473601da-3758-5b8f-84b4-daaf898d3a65', 'ride', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ɹaɪd/', 'audio/ride.mp3', 'An instance of riding.', 'Can I have a ride on your bike?', 'Travel & Transport', 'cưỡi, đi nhờ', 'Một lần cưỡi/đi.', 'Tôi có thể đi nhờ xe đạp của bạn được không?'),
    ('8b8e3b85-955a-57aa-abbd-d7af4ecca18c', '473601da-3758-5b8f-84b4-daaf898d3a65', 'road', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɹəʊd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/road-uk.mp3', 'A way used for travelling between places, originally one wide enough to allow foot passengers and horses to travel, now (US) usually one surfaced with asphalt or concrete and designed to accommodate many vehicles travelling in both directions. In the UK both senses are heard: a country road is the same as a country lane.', 'We travelled to the seaside by road.', 'Travel & Transport', 'con đường', 'Một lối đi được sử dụng để di chuyển giữa các địa điểm, ban đầu đủ rộng để người đi bộ và ngựa đi lại, nay (Mỹ) thường là lối được trải nhựa hoặc bê tông và được thiết kế để phù hợp với ô tô.', 'Chúng tôi đi đến bờ biển bằng đường bộ.'),
    ('ed79d2a1-2899-595c-979f-af12d41f667c', '473601da-3758-5b8f-84b4-daaf898d3a65', 'station', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsteɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/station-au.mp3', 'A stopping place.', 'She had ambitions beyond her station.', 'Travel & Transport', 'nhà ga', 'Một điểm dừng.', 'Cô ấy có những tham vọng vượt quá địa vị của mình.'),
    ('3d78af16-fdc7-5d1a-9899-d7f6c7e5c04d', '473601da-3758-5b8f-84b4-daaf898d3a65', 'stay', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/steɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stay-us.mp3', 'Continuance or a period of time spent in a place; abode for an indefinite time; sojourn.', 'I hope you enjoyed your stay in Hawaii.', 'Travel & Transport', 'ở lại', 'Sự tiếp tục hoặc một khoảng thời gian ở lại một nơi; nơi ở trong một thời gian không xác định; sự lưu trú.', 'Tôi hy vọng bạn đã tận hưởng kỳ nghỉ ở Hawaii của mình.'),
    ('6edec9b6-b262-5ddb-95f9-6d7635fc68d5', '473601da-3758-5b8f-84b4-daaf898d3a65', 'stop', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/stɒp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stop-uk.mp3', 'A (usually marked) place where buses, trams or trains halt to let passengers get on and off, usually smaller than a station.', 'They agreed to meet at the bus stop.', 'Travel & Transport', 'điểm dừng', 'Một nơi (thường được đánh dấu) nơi xe buýt, xe điện hoặc tàu hỏa dừng lại để cho hành khách lên xuống, thường nhỏ hơn một nhà ga.', 'Họ đồng ý gặp nhau ở trạm xe buýt.'),
    ('cc467b4a-082b-50b9-9db0-f43c94aa096b', '473601da-3758-5b8f-84b4-daaf898d3a65', 'street', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/stɹiːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/street-uk.mp3', 'A paved part of road, usually in a village or a town.', 'Walk down the street until you see a hotel on the right.', 'Travel & Transport', 'đường phố', 'Phần đường được trải nhựa, thường ở làng hoặc thị trấn.', 'Đi xuống con đường cho đến khi bạn thấy một khách sạn bên phải.'),
    ('b0346f89-33da-567e-99c8-aa7c79ad928b', '473601da-3758-5b8f-84b4-daaf898d3a65', 'taxi', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈtæk.si/', 'https://api.dictionaryapi.dev/media/pronunciations/en/taxi-uk.mp3', 'A vehicle that may be hired for single journeys by members of the public, driven by a taxi driver.', 'taxi down the runway', 'Travel & Transport', 'xe taxi', 'Một phương tiện mà công chúng có thể thuê cho các chuyến đi đơn lẻ, do tài xế taxi lái.', 'lăn bánh xuống đường băng'),
    ('767f7f37-ce7d-5e85-8134-f9a368c7a14d', '473601da-3758-5b8f-84b4-daaf898d3a65', 'ticket', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈtɪkɪt/', 'audio/ticket.mp3', 'A pass entitling the holder to admission to a show, concert, etc.', 'Joe has joined the party''s ticket for the county elections.', 'Travel & Transport', 'vé', 'Một tấm vé cho phép người giữ được vào xem một buổi biểu diễn, hòa nhạc, v.v.', 'Joe đã tham gia vào danh sách ứng cử viên của đảng cho các cuộc bầu cử hạt.'),
    ('d91af0c3-ca06-50e1-a825-bf73b8ffe8e3', '473601da-3758-5b8f-84b4-daaf898d3a65', 'traffic', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈtɹæfɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/traffic-us.mp3', 'Pedestrians or vehicles on roads, or the flux or passage thereof.', 'The traffic is slow during rush hour.', 'Travel & Transport', 'giao thông', 'Người đi bộ hoặc phương tiện trên đường, hoặc lưu lượng hay sự di chuyển của chúng.', 'Giao thông chậm trong giờ cao điểm.'),
    ('ab5207bf-f076-5503-9341-45e8e01f280c', '473601da-3758-5b8f-84b4-daaf898d3a65', 'train', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/tɹeɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/train-1-au.mp3', 'Elongated portion.', 'She trained seven hours a day to prepare for the Olympics.', 'Travel & Transport', 'tàu hỏa, huấn luyện', 'Phần kéo dài.', 'Cô ấy đã tập luyện bảy giờ một ngày để chuẩn bị cho Thế vận hội.'),
    ('11aea26c-70cd-5465-b086-019f226bd312', '473601da-3758-5b8f-84b4-daaf898d3a65', 'travel', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ˈtɹævəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/travel-us.mp3', 'The act of traveling; passage from place to place.', 'space travel', 'Travel & Transport', 'du lịch, đi lại', 'Hành động đi du lịch; di chuyển từ nơi này đến nơi khác.', 'du hành vũ trụ'),
    ('977dd5f9-ac44-5263-b2d8-02c686667008', '473601da-3758-5b8f-84b4-daaf898d3a65', 'trip', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/tɹɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/trip-1-uk.mp3', 'A journey; an excursion or jaunt', 'We made a trip to the beach.', 'Travel & Transport', 'chuyến đi', 'Một cuộc hành trình; một chuyến tham quan hoặc chuyến đi chơi ngắn', 'Chúng tôi đã có một chuyến đi đến bãi biển.'),
    ('f94e28c1-04b5-59c1-861a-daa8e7f32a38', '473601da-3758-5b8f-84b4-daaf898d3a65', 'vacation', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/veɪˈkeɪʃ(ə)n/', 'audio/vacation.mp3', 'Freedom from some business or activity.', 'The Conservative Party’s vacation of the centre ground gave an opportunity to its opponents.', 'Travel & Transport', 'kỳ nghỉ', 'Sự tự do khỏi một số công việc hoặc hoạt động.', 'Việc Đảng Bảo thủ rời bỏ vị trí trung tâm đã tạo cơ hội cho các đối thủ của họ.'),
    ('a8a219ed-b24e-5be9-82a6-8fa8ac13face', '473601da-3758-5b8f-84b4-daaf898d3a65', 'bag', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbæːɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bag-au.mp3', 'A flexible container made of cloth, paper, plastic, etc.', 'Acid House is not my bag: I prefer the more traditional styles of music.', 'Shopping & Money', 'túi, cặp', 'Một vật chứa linh hoạt làm bằng vải, giấy, nhựa, v.v.', 'Acid House không phải gu của tôi: Tôi thích các thể loại âm nhạc truyền thống hơn.'),
    ('68c24b10-ba9c-5954-aa83-390c5c383cac', '473601da-3758-5b8f-84b4-daaf898d3a65', 'buy', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/baɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/buy-uk.mp3', 'Something which is bought; a purchase.', 'At only $30, the second-hand kitchen table was a great buy.', 'Shopping & Money', 'mua', 'Thứ gì đó được mua; một món hàng mua.', 'Chỉ với 30 đô la, chiếc bàn bếp cũ là một món hời.'),
    ('9055c26a-2c3b-5ae6-a836-031210c2d737', '473601da-3758-5b8f-84b4-daaf898d3a65', 'cent', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/sɛnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cent-us.mp3', '(money) A subunit of currency equal to one-hundredth of the main unit of currency in many countries. Symbol: ¢.', 'He blew every last cent.', 'Shopping & Money', 'xu', '(tiền) Một đơn vị tiền tệ phụ bằng một phần trăm đơn vị tiền tệ chính ở nhiều quốc gia. Ký hiệu: ¢.', 'Anh ta tiêu sạch đến đồng xu cuối cùng.'),
    ('ad7c94c2-c956-54fd-8da7-7b1affd50f10', '473601da-3758-5b8f-84b4-daaf898d3a65', 'cheap', 'A1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "B1"}]'::jsonb, '/t͡ʃiːp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cheap-uk.mp3', 'Trade; traffic; chaffer; chaffering.', 'the cheap trick of hiding deadly lava under pushable blocks', 'Shopping & Money', 'rẻ', 'Buôn bán; giao dịch; mặc cả; sự mặc cả.', 'mẹo rẻ tiền khi giấu dung nham chết người dưới các khối có thể đẩy'),
    ('d39c5cd7-1ec3-5666-8d91-a9c8dc21bd69', '473601da-3758-5b8f-84b4-daaf898d3a65', 'cost', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ˈkɑst/', 'audio/cost.mp3', 'To incur a charge of; to require payment of a (specified) price.', 'It will cost you a lot of money to take a trip around the world.', 'Shopping & Money', 'chi phí', 'Phải chịu một khoản phí; yêu cầu thanh toán một mức giá (được chỉ định).', 'Sẽ tốn rất nhiều tiền để bạn thực hiện một chuyến đi vòng quanh thế giới.'),
    ('5450f842-57c0-5250-a17a-5bce704bbc82', '473601da-3758-5b8f-84b4-daaf898d3a65', 'customer', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkʌstəmə/', 'audio/customer.mp3', 'A patron, a client; one who purchases or receives a product or service from a business or merchant, or intends to do so.', 'Every person who passes by is a potential customer.', 'Shopping & Money', 'khách hàng', 'Một khách hàng quen, một thân chủ; người mua hoặc nhận sản phẩm/dịch vụ từ một doanh nghiệp hoặc thương nhân, hoặc có ý định làm như vậy.', 'Mỗi người đi ngang qua đều là một khách hàng tiềm năng.'),
    ('75bc3dce-4b26-58a3-bd06-206605cc5fb0', '473601da-3758-5b8f-84b4-daaf898d3a65', 'expensive', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ɛkˈspɛnsɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/expensive-uk.mp3', 'Given to expending a lot of money; profligate, lavish.', 'an unnecessarily expensive choice of algorithm', 'Shopping & Money', 'đắt tiền', 'Có xu hướng tiêu nhiều tiền; hoang phí, xa xỉ.', 'một lựa chọn thuật toán đắt tiền không cần thiết'),
    ('c8826ee9-dd3e-5e21-9593-4ce450943c25', '473601da-3758-5b8f-84b4-daaf898d3a65', 'money', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmʌni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/money-uk.mp3', 'A legally or socially binding conceptual contract of entitlement to wealth, void of intrinsic value, payable for all debts and taxes, and regulated in supply.', 'Before colonial times cowry shells imported from Mauritius were used as money in Western Africa.', 'Shopping & Money', 'tiền', 'Một khái niệm hợp đồng ràng buộc về mặt pháp lý hoặc xã hội về quyền được hưởng của cải, không có giá trị nội tại, có thể thanh toán cho mọi khoản nợ và thuế, và được điều chỉnh về nguồn cung.', 'Trước thời thuộc địa, vỏ ốc nhập khẩu từ Mauritius được sử dụng làm tiền ở Tây Phi.'),
    ('21110f17-b495-5cf4-95ab-7d3daa62c92a', '473601da-3758-5b8f-84b4-daaf898d3a65', 'own', 'A1', '["adj", "pron", "v"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "pron", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈəʊn/', 'audio/own.mp3', 'Belonging to; possessed; proper to. Often marks a possessive determiner as reflexive, referring back to the subject of the clause or sentence.', 'When we move into the new house, the kids will each have their own bedroom.', 'Shopping & Money', 'sở hữu', 'Thuộc về; được sở hữu; thích hợp với. Thường đánh dấu một từ xác định sở hữu như phản thân, đề cập trở lại chủ ngữ của mệnh đề hoặc câu.', 'Khi chúng tôi chuyển đến ngôi nhà mới, bọn trẻ mỗi đứa sẽ có phòng ngủ riêng của chúng.'),
    ('d59a0ae8-d1b5-5860-aac4-05a6d524f72b', '473601da-3758-5b8f-84b4-daaf898d3a65', 'pay', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/peɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pay-us.mp3', 'Money given in return for work; salary or wages.', 'Many employers have rules designed to keep employees from comparing their pays.', 'Shopping & Money', 'trả tiền, lương', 'Tiền được đưa để đổi lấy công việc; tiền lương hoặc tiền công.', 'Nhiều nhà tuyển dụng có quy tắc nhằm ngăn nhân viên so sánh mức lương của họ.'),
    ('663dac52-30b9-5cf3-b4dc-593942bffea5', '473601da-3758-5b8f-84b4-daaf898d3a65', 'price', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/pɹaɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/price-uk.mp3', 'The cost required to gain possession of something.', 'I paid a high price for my folly.', 'Shopping & Money', 'giá cả', 'Chi phí cần thiết để sở hữu một thứ gì đó.', 'Tôi đã phải trả một cái giá đắt cho sự dại dột của mình.'),
    ('b84d56a4-8487-52aa-87bb-e5cdf42faa95', '473601da-3758-5b8f-84b4-daaf898d3a65', 'shop', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ʃɒp/', 'audio/shop.mp3', 'An establishment that sells goods or services to the public; originally only a physical location, but now a virtual establishment as well.', 'This is where I do my weekly shop.', 'Shopping & Money', 'cửa hàng', 'Một cơ sở bán hàng hóa hoặc dịch vụ cho công chúng; ban đầu chỉ là địa điểm vật lý, nhưng giờ cũng là cơ sở ảo.', 'Đây là nơi tôi mua sắm hàng tuần.'),
    ('4c944d92-61fb-5773-85fe-bdce318f6712', '473601da-3758-5b8f-84b4-daaf898d3a65', 'shopping', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈʃɒpɪŋ/', 'audio/shopping.mp3', 'To visit stores or shops to browse or explore merchandise, especially with the intention of buying such merchandise.', 'He’s shopping for clothes.', 'Shopping & Money', 'mua sắm', 'Đến thăm các cửa hàng để xem hoặc khám phá hàng hóa, đặc biệt với ý định mua chúng.', 'Anh ấy đang mua sắm quần áo.'),
    ('c1ab658b-61be-5752-88af-13e876e808ff', '473601da-3758-5b8f-84b4-daaf898d3a65', 'special', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈspɛ.ʃəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/special-us.mp3', 'A reduction in consumer cost (usually for a limited time) for items or services rendered.', 'We''re running a special on turkey for Thanksgiving.', 'Shopping & Money', 'đặc biệt', 'Một khoản giảm giá cho người tiêu dùng (thường trong thời gian giới hạn) cho các mặt hàng hoặc dịch vụ được cung cấp.', 'Chúng tôi đang có chương trình khuyến mãi đặc biệt cho gà tây vào Lễ Tạ ơn.'),
    ('e7afa405-b6da-5a80-9303-020105a40816', '473601da-3758-5b8f-84b4-daaf898d3a65', 'spend', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/spɛnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/spend-us.mp3', 'Amount of money spent (during a period); expenditure.', 'I’m sorry, boss, but the advertising spend exceeded the budget again this month.', 'Shopping & Money', 'tiêu tiền', 'Số tiền đã chi tiêu (trong một khoảng thời gian); chi tiêu.', 'Tôi xin lỗi, sếp, nhưng chi phí quảng cáo lại vượt quá ngân sách trong tháng này.'),
    ('89bb83ca-9b49-5912-a8dc-aae337b7b81c', '473601da-3758-5b8f-84b4-daaf898d3a65', 'supermarket', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˌsuːpəˈmɑːkɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/supermarket-uk.mp3', 'A large self-service store that sells groceries and, usually, medications, household goods and/or clothing.', 'I went to the supermarket to buy some food.', 'Shopping & Money', 'siêu thị', 'Một cửa hàng tự phục vụ lớn bán thực phẩm và, thường là, thuốc men, hàng gia dụng và/hoặc quần áo.', 'Tôi đã đi siêu thị để mua một ít thức ăn.'),
    ('04be3c1a-502f-53e9-a264-32259f2ddb32', '473601da-3758-5b8f-84b4-daaf898d3a65', 'bicycle', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbaɪsɪkl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bicycle-au.mp3', 'A vehicle that has two wheels, one behind the other, a steering handle, and a saddle seat or seats and is usually propelled by the action of a rider’s feet upon pedals.', NULL, 'Travel & Transport', 'xe đạp', 'Một phương tiện có hai bánh xe, một trước một sau, một tay lái, và một yên ngồi hoặc nhiều yên và thường được đẩy bằng động tác đạp bàn đạp của người lái.', NULL),
    ('077aa27c-f232-5768-b9e4-de4e6528e592', '473601da-3758-5b8f-84b4-daaf898d3a65', 'driver', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈdɹaɪ.və(ɹ)/', 'audio/driver.mp3', 'One who drives something, in any sense of the verb to drive.', NULL, 'Travel & Transport', 'tài xế, người lái', 'Người điều khiển thứ gì đó, theo bất kỳ nghĩa nào của động từ ''to drive''.', NULL),
    ('22b6de55-86da-5705-9678-66359be66364', '473601da-3758-5b8f-84b4-daaf898d3a65', 'hotel', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/(h)əʊˈtɛl/', 'audio/hotel.mp3', 'A large town house or mansion; a grand private residence, especially in France.', NULL, 'Travel & Transport', 'khách sạn', NULL, NULL),
    ('845b40a3-9a72-5330-b428-d7dfc561965e', '473601da-3758-5b8f-84b4-daaf898d3a65', 'leave', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/liːv/', 'audio/leave.mp3', 'To have a consequence or remnant.', NULL, 'Travel & Transport', 'rời đi, sự ra đi', 'Để lại một hậu quả hoặc tàn dư.', NULL),
    ('0b251282-e0be-5764-8fe3-8f89b4a2473b', '473601da-3758-5b8f-84b4-daaf898d3a65', 'tourist', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈtʊəɹɪst/', 'audio/tourist.mp3', 'Someone who travels for pleasure rather than for business.', NULL, 'Travel & Transport', 'khách du lịch', 'Người đi du lịch để giải trí hơn là vì công việc.', NULL),
    ('e5769bd5-12af-509d-a464-0405578d05a8', '473601da-3758-5b8f-84b4-daaf898d3a65', 'visit', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ˈvɪzɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/visit-us.mp3', 'A single act of visiting.', NULL, 'Travel & Transport', 'thăm viếng', 'Một hành động thăm viếng duy nhất.', NULL),
    ('33b9bf96-3aa3-5dcf-af54-f9a5195c320c', '473601da-3758-5b8f-84b4-daaf898d3a65', 'visitor', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈvɪzɪtə/', 'audio/visitor.mp3', 'Someone who visits someone else; someone staying as a guest.', NULL, 'Travel & Transport', 'khách thăm', 'Người đến thăm người khác; người ở lại với tư cách khách.', NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

