INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('c3848fd7-b0d9-5371-aa49-96d10edfca81', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'air', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɛə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/air-uk.mp3', 'The substance constituting earth''s atmosphere, particularly:', 'I''m going outside to get some air.', 'Nature & Environment', 'không khí', 'Chất tạo nên bầu khí quyển của trái đất, cụ thể là:', 'Tôi sẽ ra ngoài để hít thở không khí.'),
    ('ac9ef276-7447-51c2-a60f-8fc018999a06', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'animal', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈænɪməl/', 'audio/animal.mp3', 'In scientific usage, a multicellular organism that is usually mobile, whose cells are not encased in a rigid cell wall (distinguishing it from plants and fungi) and which derives energy solely from the consumption of other organisms (distinguishing it from plants).', 'A cat is an animal, not a plant. Humans are also animals, under the scientific definition, as we are not plants.', 'Nature & Environment', 'động vật', 'Trong cách dùng khoa học, một sinh vật đa bào thường di động, có các tế bào không được bao bọc trong thành tế bào cứng (phân biệt với thực vật và nấm) và chỉ lấy năng lượng từ...', 'Mèo là động vật, không phải thực vật. Con người cũng là động vật, theo định nghĩa khoa học, vì chúng ta không phải thực vật.'),
    ('aaab33de-65b8-5f6d-ad49-017e3565d8b9', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'bird', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɜd/', 'audio/bird.mp3', 'A member of the class of animals Aves in the phylum Chordata, characterized by being warm-blooded, having feathers and wings usually capable of flight, and laying eggs.', 'Ducks and sparrows are birds.', 'Nature & Environment', 'con chim', 'Một thành viên của lớp động vật Aves trong ngành Chordata, đặc trưng bởi việc là động vật máu nóng, có lông vũ và cánh thường có khả năng bay, và đẻ trứng.', 'Vịt và chim sẻ là các loài chim.'),
    ('dd1d8e89-4450-57a9-a9af-75471c3937d0', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'dog', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/dɑɡ/', 'audio/dog.mp3', 'A mammal, Canis familiaris or Canis lupus familiaris, that has been domesticated for thousands of years, of highly variable appearance due to human breeding.', 'The dog barked all night long.', 'Nature & Environment', 'con chó', 'Một loài động vật có vú, Canis familiaris hoặc Canis lupus familiaris, đã được thuần hóa trong hàng nghìn năm, với ngoại hình rất đa dạng do con người lai tạo.', 'Con chó sủa suốt đêm.'),
    ('dabe89d0-59f5-55c8-b622-82fe617a9da8', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'east', 'A1', '["n", "adj", "adv"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/iːst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/east-uk.mp3', 'One of the four principal compass points, specifically 90°, conventionally directed to the right on maps; the direction of the rising sun at an equinox. Abbreviated as E.', 'the east front of a cathedral', 'Nature & Environment', 'phía đông, hướng đông', 'Một trong bốn điểm chính của la bàn, cụ thể là 90°, thường được chỉ về bên phải trên bản đồ; hướng mặt trời mọc vào thời điểm phân. Viết tắt là E.', 'mặt tiền phía đông của một nhà thờ lớn'),
    ('417b4415-aeef-5a96-b125-da0d06661e5f', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'elephant', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɛləfənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/elephant-us.mp3', 'A mammal of the order Proboscidea, having a trunk, and two large ivory tusks jutting from the upper jaw.', 'Let''s play hide and seek. I''ll count. One elephant, two elephant, three elephant...', 'Nature & Environment', 'con voi', 'Một loài động vật có vú thuộc bộ Có vòi, có vòi, và hai chiếc ngà lớn nhô ra từ hàm trên.', 'Hãy chơi trốn tìm. Tôi sẽ đếm. Một con voi, hai con voi, ba con voi...'),
    ('e9dd7135-051c-556d-ba00-636d77630d30', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'fire', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈfɑeə(ɹ)/', 'audio/fire.mp3', 'A (usually self-sustaining) chemical reaction involving the bonding of oxygen with carbon or other fuel, with the production of heat and the presence of flame or smouldering.', 'We sat about the fire singing songs and telling tales.', 'Nature & Environment', 'lửa', 'Một phản ứng hóa học (thường tự duy trì) liên quan đến sự liên kết của oxy với carbon hoặc nhiên liệu khác, tạo ra nhiệt và có sự hiện diện của ngọn lửa hoặc âm ỉ.', 'Chúng tôi ngồi quanh đống lửa hát hò và kể chuyện.'),
    ('8d4613c2-d8a8-518d-aa9e-3df377eb587b', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'flower', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈflaʊ.ə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/flower-1-uk.mp3', 'A colorful, conspicuous structure associated with angiosperms, frequently scented and attracting various insects, and which may or may not be used for sexual reproduction.', 'We transplanted the flowers to a larger pot.', 'Nature & Environment', 'hoa', 'Một cấu trúc đầy màu sắc, nổi bật liên quan đến thực vật hạt kín, thường có mùi thơm và thu hút nhiều loại côn trùng, và có thể hoặc không được sử dụng cho sinh sản hữu tính.', 'Chúng tôi đã chuyển những bông hoa sang một chậu lớn hơn.'),
    ('105ef000-a186-5c0d-962f-ccb3c3188316', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'grow', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/ɡɹəʊ/', 'audio/grow.mp3', 'To become larger, to increase in magnitude.', 'Children grow quickly.', 'Nature & Environment', 'phát triển / lớn lên', 'Trở nên lớn hơn, tăng về quy mô.', 'Trẻ con lớn nhanh.'),
    ('78f069a6-cff0-53fe-8c58-70abe443eab4', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'ice', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '[ʌɪs]', 'audio/ice.mp3', 'Water in frozen (solid) form.', 'Milton Keynes have yet to ice a team this season', 'Nature & Environment', 'băng', 'Nước ở dạng đông đặc (rắn).', 'Milton Keynes vẫn chưa có đội bóng chày nào ra sân trong mùa giải này'),
    ('f10e7df0-28ae-59fe-86a7-9da548c45228', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'island', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈaɪ̯lənd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/island-uk.mp3', 'A contiguous area of land, smaller than a continent, totally surrounded by water.', 'an island of colors on a butterfly''s wing', 'Nature & Environment', 'hòn đảo', 'Một vùng đất liền tục, nhỏ hơn lục địa, hoàn toàn được bao quanh bởi nước.', 'một đảo màu sắc trên cánh bướm'),
    ('cf1100ff-1e78-5804-a6c6-6c06462e164a', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'land', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/lænd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/land-us.mp3', 'The part of Earth which is not covered by oceans or other bodies of water.', 'Most insects live on land.', 'Nature & Environment', 'đất liền', 'Phần của Trái Đất không bị bao phủ bởi đại dương hoặc các vùng nước khác.', 'Hầu hết côn trùng sống trên đất liền.'),
    ('8f671eae-1c73-59d5-8151-d7ec87e177b6', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'lion', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈlaɪən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lion-us.mp3', 'A big cat, Panthera leo, native to Africa, India and formerly much of Europe.', 'Tigers and lions share a common ancestor from a few million years ago.', 'Nature & Environment', 'sư tử', 'Một loài mèo lớn, Panthera leo, có nguồn gốc từ Châu Phi, Ấn Độ và trước đây là phần lớn Châu Âu.', 'Hổ và sư tử có chung một tổ tiên từ vài triệu năm trước.'),
    ('682e7d59-b5c2-5fd4-8aa0-9b0ae82af4ed', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'mountain', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmaʊntɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mountain-uk.mp3', 'An elevation of land of considerable dimensions rising more or less abruptly, forming a conspicuous figure in the landscape, usually having a small extent of surface at its summit.', 'We spent the weekend hiking in the mountains.', 'Nature & Environment', 'núi', 'Một độ cao của đất có kích thước đáng kể dâng lên ít nhiều đột ngột, tạo thành một hình dáng nổi bật trong cảnh quan, thường có một diện tích bề mặt nhỏ ở đỉnh của nó.', 'Chúng tôi đã dành cuối tuần để đi bộ đường dài trên núi.'),
    ('afcbbd8f-0fb7-5b14-9d2e-04c68696f23f', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'natural', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/ˈnætʃəɹəl/', 'audio/natural.mp3', 'A native inhabitant of a place, country etc.', 'He''s a natural on the saxophone.', 'Nature & Environment', 'tự nhiên', 'Một cư dân bản địa của một nơi, đất nước, v.v.', 'Anh ấy chơi saxophone rất tự nhiên.'),
    ('45c162c7-f563-5d43-b246-feb41554c196', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'north', 'A1', '["n", "adj", "adv"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/noːθ/', 'audio/north.mp3', 'One of the four major compass points, specifically 0°, directed toward the North Pole, and conventionally upwards on a map, abbreviated as N.', 'Minnesota is in the north of the USA.', 'Nature & Environment', 'phía bắc', 'Một trong bốn điểm chính của la bàn, cụ thể là 0°, hướng về Cực Bắc, và theo quy ước là hướng lên trên bản đồ, viết tắt là N.', 'Minnesota nằm ở phía bắc của Hoa Kỳ.'),
    ('6d2fb59c-d354-5571-9671-d872accf9b36', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'park', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '[paːk]', 'https://api.dictionaryapi.dev/media/pronunciations/en/park-au.mp3', 'An area of land set aside for environment preservation or recreation.', 'A country''s tank park or artillery park.', 'Nature & Environment', 'công viên, đỗ xe', 'Một khu đất được dành riêng để bảo tồn môi trường hoặc giải trí.', 'Khu vực xe tăng hoặc pháo binh của một quốc gia.'),
    ('30439ed5-8f65-5e25-a901-8297236fb3a8', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'plant', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/plænt/', 'audio/plant.mp3', 'An organism that is not an animal, especially an organism capable of photosynthesis. Typically a small or herbaceous organism of this kind, rather than a tree.', 'The garden had a couple of trees, and a cluster of colourful plants around the border.', 'Nature & Environment', 'cây cối', 'Một sinh vật không phải động vật, đặc biệt là sinh vật có khả năng quang hợp. Thường là một sinh vật nhỏ hoặc thân thảo thuộc loại này, thay vì một cây lớn.', 'Khu vườn có vài cây, và một cụm cây nhiều màu sắc xung quanh viền.'),
    ('7f8dae8d-227b-57a9-8d7a-08afd3e2850b', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'pool', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/pul/', 'audio/pool.mp3', 'A small and rather deep collection of (usually) fresh water, as one supplied by a spring, or occurring in the course of a stream; a reservoir for water.', 'the pools of Solomon', 'Nature & Environment', 'hồ nước', 'Một vùng nước (thường là nước ngọt) nhỏ và khá sâu, như được cung cấp bởi một mạch suối, hoặc xuất hiện trên dòng chảy của một con suối; một hồ chứa nước.', 'những hồ nước của Solomon'),
    ('f3850b5b-24ce-5ed8-9919-deb0d46c7f8f', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'river', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɹɪvə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/river-1-uk.mp3', 'A large and often winding stream which drains a land mass, carrying water down from higher areas to a lower point, oftentimes ending in another body of water, such as an ocean or in an inland sea.', 'Occasionally rivers overflow their banks and cause floods.', 'Nature & Environment', 'dòng sông', 'Một dòng chảy lớn và thường quanh co thoát nước từ một khối đất, mang nước từ các khu vực cao hơn xuống điểm thấp hơn, thường kết thúc ở một vùng nước khác, chẳng hạn như đại dương hoặc biển nội địa.', 'Thỉnh thoảng sông tràn bờ và gây lũ lụt.'),
    ('8a0901ea-a680-5f6f-b19d-5fa208c79559', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'sea', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/siː/', 'audio/sea.mp3', 'A large body of salt water.', 'The Caspian Sea, the Sea of Galilee, the Salton Sea, etc.', 'Nature & Environment', 'biển', 'Một vùng nước mặn rộng lớn.', 'Biển Caspi, Biển Galilee, Biển Salton, v.v.'),
    ('5c2acf57-2bd9-5ba8-a433-47ddbeeaae7b', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'snake', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsneɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/snake-au.mp3', 'A legless reptile of the sub-order Serpentes with a long, thin body and a fork-shaped tongue.', 'The path snaked through the forest.', 'Nature & Environment', 'con rắn', 'Một loài bò sát không chân thuộc phân bộ Serpentes với thân hình dài, mảnh và lưỡi hình chĩa.', 'Con đường uốn lượn qua khu rừng.'),
    ('1637f71d-a144-57ce-89d2-cee4d00e2cd1', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'south', 'A1', '["n", "adj", "adv"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/sæoθ/', 'audio/south.mp3', 'One of the four major compass points, specifically 180°, directed toward the South Pole, and conventionally downwards on a map, abbreviated as S.', 'The moon souths at nine.', 'Nature & Environment', 'phía nam', 'Một trong bốn điểm chính của la bàn, cụ thể là 180°, hướng về Nam Cực, và theo quy ước là hướng xuống trên bản đồ, viết tắt là S.', 'Mặt trăng lặn về hướng nam lúc chín giờ.'),
    ('8287c027-a673-55cc-9f43-93a79d46890d', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'spring', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/spɹɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/spring-au.mp3', 'To weaken, as a joint, ligament, or muscle, by sudden and excessive exertion, as by wrenching; to overstrain, or stretch injuriously, but without luxation', 'to sprain one''s ankle', 'Nature & Environment', 'mùa xuân', 'Làm suy yếu, như một khớp, dây chằng, hoặc cơ, bằng sự gắng sức đột ngột và quá mức, như bằng cách vặn xoắn; làm căng quá mức, hoặc kéo giãn một cách gây hại, nhưng không bị trật khớp.', 'bị bong gân mắt cá chân'),
    ('c17269fb-1a5c-582a-8ca9-e1571f05b1b6', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'sun', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/sʌn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sun-uk.mp3', 'A star, especially when seen as the centre of any single solar system.', 'Beautiful bodies lying on the beach, sunning their bronzed limbs.', 'Nature & Environment', 'mặt trời', 'Một ngôi sao, đặc biệt khi được coi là trung tâm của bất kỳ hệ mặt trời đơn lẻ nào.', 'Những cơ thể đẹp đẽ nằm trên bãi biển, phơi nắng những cánh tay rám nắng của họ.'),
    ('573f589e-68bb-5919-a851-ca8128ce782c', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'tree', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/tɹiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tree-uk.mp3', 'Fast growing function based on Kruskal''s tree theorem.', 'Birds have a nest in a tree in the garden.', 'Nature & Environment', 'cây', 'Hàm tăng trưởng nhanh dựa trên định lý cây của Kruskal.', 'Chim có một cái tổ trên cây trong vườn.'),
    ('d388338a-c4e8-50f5-aa3d-681488322177', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'water', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈwoːtə/', 'audio/water.mp3', 'A substance (of molecular formula H₂O) found at room temperature and pressure as a clear liquid; it is present naturally as rain, and found in rivers, lakes and seas; its solid form is ice and its gaseous form is steam.', 'By the action of electricity, the water was resolved into its two parts, oxygen and hydrogen.', 'Nature & Environment', 'nước', 'Một chất (có công thức phân tử H₂O) được tìm thấy ở nhiệt độ và áp suất phòng dưới dạng chất lỏng trong suốt; nó có tự nhiên dưới dạng mưa và được tìm thấy trong sông, hồ và biển; dạng rắn của nó là băng và dạng khí.', 'Bằng tác động của điện, nước được phân giải thành hai phần, oxy và hydro.'),
    ('1f33d332-329b-55cb-80b1-6e5a88a9f0dd', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'autumn', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɔːtəm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/autumn-uk.mp3', 'Traditionally the third of the four seasons, when deciduous trees lose their leaves; typically regarded as being from September 24 to December 22 in parts of the Northern Hemisphere, and the months of March, April and May in the Southern Hemisphere.', 'autumn leaves', 'Weather & Climate', 'mùa thu', 'Theo truyền thống là mùa thứ ba trong bốn mùa, khi cây rụng lá; thường được coi là từ ngày 24 tháng 9 đến ngày 22 tháng 12 ở một số nơi thuộc Bắc Bán cầu, và các tháng của (mùa thu ở Nam Bán cầu).', 'lá mùa thu'),
    ('9ed1faa4-e852-5f1f-a15c-b8f12f0e59e5', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'cold', 'A1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/kɔʊld/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cold-uk.mp3', '(of a thing) Having a low temperature.', 'A cold wind whistled through the trees.', 'Weather & Climate', 'lạnh', '(của một vật) Có nhiệt độ thấp.', 'Một cơn gió lạnh rít qua những tán cây.'),
    ('a0d996e3-1bec-54e5-af39-4ce995396f12', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'hot', 'A1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A1"}]'::jsonb, '/hɒt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hot-uk.mp3', '(with up) To heat; to make or become hot.', 'He forgot that the frying pan was hot and burned his hand.', 'Weather & Climate', 'nóng', '(với up) Để làm nóng; để làm hoặc trở nên nóng.', 'Anh ấy quên rằng chảo chiên đang nóng và bị bỏng tay.'),
    ('91cd86b5-bef0-5ee9-94ba-4c766ce56bb5', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'rain', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ɹeɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rain-uk.mp3', 'Condensed water falling from a cloud.', 'The rains came late that year.', 'Weather & Climate', 'mưa', 'Nước ngưng tụ rơi từ một đám mây.', 'Năm đó, mùa mưa đến muộn.'),
    ('50cb2470-26ae-5fcb-acc5-f4e9a9ecf75c', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'shower', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈʃaʊ.ə(ɹ)/', 'audio/shower.mp3', 'A brief fall of precipitation (spell of rain, or a similar fall of snow, sleet, or cascade).', 'Today there will be frequent showers and some sunny spells.', 'Weather & Climate', 'cơn mưa rào', 'Một đợt mưa ngắn (cơn mưa, hoặc một đợt tuyết, mưa tuyết, hoặc dòng chảy tương tự).', 'Hôm nay sẽ có những cơn mưa rào thường xuyên và một số khoảng thời gian nắng.'),
    ('9d184861-c2bd-59a7-b337-8b47a804a44b', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'snow', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/snəʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/snow-1-uk.mp3', 'The frozen, crystalline state of water that falls as precipitation.', 'We have had several heavy snows this year.', 'Weather & Climate', 'tuyết', 'Trạng thái đông đặc, dạng tinh thể của nước rơi xuống dưới dạng giáng thủy.', 'Năm nay chúng tôi đã có vài trận tuyết rơi dày.'),
    ('1c4545a5-3f3a-5441-b2b4-4db39b2e4c94', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'summer', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsʌmə(ɹ)/', 'audio/summer.mp3', 'One of four seasons, traditionally the second, marked by the longest and typically hottest days of the year due to the inclination of the Earth and thermal lag. Typically regarded as being from June 21 to September 22 or 23 in parts of the USA, the months of June, July and August in the United Kingdom and the months of December, January and February in the Southern Hemisphere.', 'the heat of summer', 'Weather & Climate', 'mùa hè', 'Một trong bốn mùa, theo truyền thống là mùa thứ hai, được đánh dấu bằng những ngày dài nhất và thường nóng nhất trong năm do độ nghiêng của Trái đất và độ trễ nhiệt. Thường được coi là từ ngày 2 tháng 6', 'cái nóng của mùa hè'),
    ('5157d51f-6bde-5adf-9494-e4c07193116b', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'warm', 'A1', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/wɔːm/', 'audio/warm.mp3', 'Having a temperature slightly higher than usual, but still pleasant; mildly hot.', 'The tea is still warm.', 'Weather & Climate', 'ấm áp', 'Có nhiệt độ cao hơn một chút so với bình thường, nhưng vẫn dễ chịu; hơi nóng.', 'Trà vẫn còn ấm.'),
    ('dc3814c9-3921-5b1c-b050-8703717b6e04', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'weather', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈwɛðə/', 'audio/weather.mp3', 'The short term state of the atmosphere at a specific time and place, including the temperature, relative humidity, cloud cover, precipitation, wind, etc.', 'Wooden garden furniture must be well oiled as it is continuously exposed to weather.', 'Weather & Climate', 'thời tiết', 'Trạng thái ngắn hạn của khí quyển tại một thời điểm và địa điểm cụ thể, bao gồm nhiệt độ, độ ẩm tương đối, độ che phủ của mây, lượng mưa, gió, v.v.', 'Đồ nội thất vườn bằng gỗ phải được tra dầu kỹ vì nó liên tục tiếp xúc với thời tiết.'),
    ('25136152-22c5-511a-a292-8c8def3ec5a0', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'winter', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈwɪntɚ/', 'audio/winter.mp3', 'Traditionally the fourth of the four seasons, typically regarded as being from December 23 to March 20 in continental regions of the Northern Hemisphere or the months of June, July and August in the Southern Hemisphere. It is the time when the sun is lowest in the sky, resulting in short days, and the time of year with the lowest atmospheric temperatures for the region.', 'When they retired, they hoped to winter in Florida.', 'Weather & Climate', 'mùa đông', 'Truyền thống là mùa thứ tư trong bốn mùa, thường được coi là từ ngày 23 tháng 12 đến ngày 20 tháng 3 ở các khu vực lục địa của Bán cầu Bắc hoặc các tháng Sáu, Bảy và Tám ở Bán cầu Nam.', 'Khi họ nghỉ hưu, họ hy vọng sẽ tránh đông ở Florida.'),
    ('2893f977-a29e-586b-9f03-0b28f705b529', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'beach', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/biːt͡ʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/beach-uk.mp3', 'The shore of a body of water, especially when sandy or pebbly.', NULL, 'Nature & Environment', 'bãi biển', 'Bờ của một vùng nước, đặc biệt khi có cát hoặc sỏi.', NULL),
    ('516c8706-faf4-5eb8-ac9d-b39eddfc9045', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'cow', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/kaʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cow-uk.mp3', '(properly) An adult female of the species Bos taurus, especially one that has calved.', NULL, 'Nature & Environment', 'con bò cái', '(Chính xác) Một con cái trưởng thành của loài Bos taurus, đặc biệt là một con đã đẻ.', NULL),
    ('4892e6f7-6e72-54a5-8e91-af3d2159cc0d', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'fly', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/flaɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fly-us.mp3', 'Any insect of the order Diptera; characterized by having two wings (except for some wingless species), also called true flies.', NULL, 'Nature & Environment', 'con ruồi', 'Bất kỳ loài côn trùng nào thuộc bộ Diptera; đặc trưng bởi việc có hai cánh (ngoại trừ một số loài không cánh), còn gọi là ruồi thật sự.', NULL),
    ('873ad909-282c-5abc-bd51-d70009441b14', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'horse', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/hɔːs/', 'audio/horse.mp3', 'Any of several animals related to Equus ferus caballus.', NULL, 'Nature & Environment', 'ngựa', NULL, NULL),
    ('d36dc07d-d889-5914-886f-a144bf12a6a0', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'sheep', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ʃiːp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sheep-uk.mp3', 'A woolly ruminant of the genus Ovis.', NULL, 'Nature & Environment', 'con cừu', 'Một loài động vật nhai lại có lông thuộc chi Ovis.', NULL),
    ('cace60c1-05aa-50e7-a41a-e86e27d4dd7e', 'a3ef302c-800c-568c-87d7-44db9e34e35f', 'west', 'A1', '["n", "adj", "adv"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/wɛst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/west-uk.mp3', 'One of the four principal compass points, specifically 270°, conventionally directed to the left on maps; the direction of the setting sun at an equinox, abbreviated as W.', NULL, 'Nature & Environment', 'phía tây', 'Một trong bốn điểm chính của la bàn, cụ thể là 270°, thường được chỉ về bên trái trên bản đồ; hướng mặt trời lặn vào thời điểm phân, viết tắt là W.', NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

