INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('d4424500-c747-59e8-a886-ad4ba20e112f', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'art', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɑːt/', 'audio/art.mp3', 'The conscious production or arrangement of sounds, colours, forms, movements, or other elements in a manner that affects the senses and emotions, usually specifically the production of the beautiful in a graphic or plastic medium.', 'There is a debate as to whether graffiti is art or vandalism.', 'Arts & Entertainment', 'nghệ thuật', 'Sự sản xuất hoặc sắp xếp có ý thức các âm thanh, màu sắc, hình dạng, chuyển động, hoặc các yếu tố khác theo cách tác động đến giác quan và cảm xúc, thường cụ thể là sự sản xuất ra cái đẹp.', 'Có một cuộc tranh luận về việc graffiti là nghệ thuật hay hành vi phá hoại.'),
    ('93685c25-b9f4-5045-a616-939467c798ea', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'band', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bænd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/band-ca.mp3', 'A strip of material used for strengthening or coupling.', 'valence band; conduction band', 'Arts & Entertainment', 'ban nhạc, dải', 'Một dải vật liệu được sử dụng để gia cố hoặc kết nối.', 'vùng hóa trị; vùng dẫn'),
    ('b4b96865-894b-563d-b2c6-7d68ea736ded', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'cinema', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈsɪn.ɪ.mɑː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cinema-uk.mp3', 'A movie theatre, a movie house', 'The cinema is right across the street from the restaurant.', 'Arts & Entertainment', 'rạp chiếu phim', 'Một rạp chiếu phim, một nhà chiếu phim.', 'Rạp chiếu phim nằm ngay bên kia đường từ nhà hàng.'),
    ('b45787dc-a348-5b23-9a63-5ae8723f9acd', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'concert', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkɒnsət/', 'audio/concert.mp3', 'Agreement in a design or plan; union formed by mutual communication of opinions and views; accordance in a scheme; harmony; simultaneous action.', 'I''m going to the rock concert on Friday.', 'Arts & Entertainment', 'buổi hòa nhạc', 'Sự đồng thuận trong một thiết kế hoặc kế hoạch; sự liên kết được hình thành bởi sự trao đổi ý kiến và quan điểm lẫn nhau; sự phù hợp trong một kế hoạch; sự hài hòa; hành động đồng thời.', 'Tôi sẽ đi xem buổi hòa nhạc rock vào thứ Sáu.'),
    ('a275f140-a87c-547c-affb-67b346efbbd9', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'create', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/kɹiːˈeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/create-us.mp3', 'To bring into existence; (sometimes in particular:)', 'You can create the color orange by mixing yellow and red.', 'Arts & Entertainment', 'tạo ra', 'Mang vào sự tồn tại; (đôi khi cụ thể:)', 'Bạn có thể tạo ra màu cam bằng cách trộn màu vàng và đỏ.'),
    ('9cbe895a-1061-5522-acfd-38496249c268', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'dance', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '[dæːns]', 'audio/dance.mp3', 'A sequence of rhythmic steps or movements usually performed to music, for pleasure or as a form of social interaction.', 'So how much longer are we gonna do this dance?', 'Arts & Entertainment', 'nhảy múa', 'Một chuỗi các bước hoặc chuyển động nhịp nhàng thường được thực hiện theo nhạc, để giải trí hoặc như một hình thức tương tác xã hội.', 'Vậy chúng ta sẽ còn làm điệu nhảy này bao lâu nữa?'),
    ('80c511a3-f67d-5f73-b2a7-416ffe2535bc', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'dancing', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈdæn.sɪŋ/', 'audio/dancing.mp3', 'To move with rhythmic steps or movements, especially in time to music.', 'I danced with her all night long.', 'Arts & Entertainment', 'khiêu vũ', 'Di chuyển với các bước hoặc chuyển động nhịp nhàng, đặc biệt là theo nhạc.', 'Tôi đã khiêu vũ với cô ấy suốt đêm.'),
    ('ba1cb69d-aec5-5807-ae80-ef0b9247b5c4', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'design', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/dɪˈzaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/design-us.mp3', 'A specification of an object or process, referring to requirements to be satisfied and thus conditions to be met for them to solve a problem.', 'To be hateful of the truth by design.', 'Arts & Entertainment', 'thiết kế', 'Một đặc tả của một đối tượng hoặc quy trình, đề cập đến các yêu cầu cần được thỏa mãn và do đó các điều kiện cần được đáp ứng để giải quyết một vấn đề.', 'Ghét sự thật một cách có chủ đích.'),
    ('b7828d45-33d9-59b5-a994-5b9e0525d19a', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'dialogue', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈdaɪəlɑɡ/', 'audio/dialogue.mp3', 'A conversation or other form of discourse between two or more individuals.', 'Bill and Melinda maintained a dialogue via email over the course of their long-distance relationship.', 'Arts & Entertainment', 'đối thoại', 'Một cuộc trò chuyện hoặc hình thức diễn ngôn khác giữa hai hoặc nhiều cá nhân.', 'Bill và Melinda duy trì một cuộc đối thoại qua email trong suốt mối quan hệ xa cách dài hạn của họ.'),
    ('8a40f73c-5e29-5d7f-a9f1-4543d2387ca8', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'film', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '[ˈfɪlm̩]', 'audio/film.mp3', 'A thin layer of some substance; a pellicle; a membranous covering, causing opacity.', 'a clear plastic film for wrapping food', 'Arts & Entertainment', 'phim, màng mỏng', 'Một lớp mỏng của một chất nào đó; một màng mỏng; một lớp phủ màng, gây ra độ mờ.', 'một màng nhựa trong suốt để gói thực phẩm'),
    ('e2a7a107-048e-5efd-9988-361c0dc0e133', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'model', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈmɒdl̩/', 'audio/model.mp3', 'A person who serves as a subject for artwork or fashion, usually in the medium of photography but also for painting or drawing.', 'The beautiful model had her face on the cover of almost every fashion magazine imaginable.', 'Arts & Entertainment', 'người mẫu, mô hình', 'Một người phục vụ như một đối tượng cho tác phẩm nghệ thuật hoặc thời trang, thường trong phương tiện nhiếp ảnh nhưng cũng cho hội họa hoặc vẽ.', 'Người mẫu xinh đẹp có khuôn mặt trên bìa của hầu hết mọi tạp chí thời trang có thể tưởng tượng được.'),
    ('5541a69a-f49f-508c-ad9c-6509a1ad60e4', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'movie', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmuːvi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/movie-us.mp3', 'A recorded sequence of images displayed on a screen at a rate sufficiently fast to create the appearance of motion.', 'Let''s go to the movies.', 'Arts & Entertainment', 'phim', 'Một chuỗi hình ảnh được ghi lại hiển thị trên màn hình với tốc độ đủ nhanh để tạo ra sự xuất hiện của chuyển động.', 'Chúng ta hãy đi xem phim.'),
    ('93b37411-72c1-597d-b202-dc2f664cf207', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'music', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmjuːzɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/music-uk.mp3', 'A series of sounds organized in time, employing melody, harmony, tempo etc. usually to convey a mood.', 'I keep listening to this music because it''s a masterpiece.', 'Arts & Entertainment', 'âm nhạc', 'Một chuỗi âm thanh được tổ chức theo thời gian, sử dụng giai điệu, hòa âm, nhịp độ... thường để truyền tải tâm trạng.', 'Tôi cứ nghe bản nhạc này vì nó là một kiệt tác.'),
    ('886f37ab-5452-58be-acfd-f3abf461392b', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'paint', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/peɪnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/paint-us.mp3', 'A substance that is applied as a liquid or paste, and dries into a solid coating that protects or adds color/colour to an object or surface to which it has been applied.', 'The Nimrods are strong on the outside, but not very good in the paint.', 'Arts & Entertainment', 'sơn, vẽ', 'Một chất được bôi dưới dạng lỏng hoặc bột nhão, và khô thành một lớp phủ rắn bảo vệ hoặc thêm màu sắc cho một vật thể hoặc bề mặt mà nó được bôi lên.', 'Đội Nimrods mạnh ở bên ngoài, nhưng không giỏi lắm trong khu vực cấm địa.'),
    ('722a0cdd-0100-578b-b271-c566de9cd1a5', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'painting', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpeɪn.tɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/painting-uk.mp3', 'To apply paint to.', 'to paint a portrait or a landscape', 'Arts & Entertainment', 'bức tranh, sự vẽ tranh', 'Bôi sơn lên.', 'vẽ một bức chân dung hoặc phong cảnh'),
    ('c61a1a56-8b10-5c2e-a9e0-6f25648842cf', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'piano', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/piˈænoʊ/', 'audio/piano.mp3', 'A percussive keyboard musical instrument, usually ranging over seven octaves, with white and black colored keys, played by pressing these keys, causing hammers to strike strings', 'He can play "Happy Birthday" on the piano.', 'Arts & Entertainment', 'đàn piano', 'Một nhạc cụ bàn phím gõ, thường có âm vực trên bảy quãng tám, với các phím màu trắng và đen, được chơi bằng cách nhấn các phím này, khiến các búa gõ vào dây đàn', 'Anh ấy có thể chơi "Happy Birthday" trên đàn piano.'),
    ('d55b0104-23ce-50e6-9a51-27c84c3f2756', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'picture', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈpɪktʃə/', 'audio/picture.mp3', 'A representation of anything (as a person, a landscape, a building) upon canvas, paper, or other surface, by drawing, painting, printing, photography, etc.', 'There was a picture hanging above the fireplace.', 'Arts & Entertainment', 'bức tranh, hình ảnh', 'Sự thể hiện của bất cứ thứ gì (như một người, một phong cảnh, một tòa nhà) trên vải, giấy hoặc bề mặt khác, bằng cách vẽ, sơn, in, chụp ảnh, v.v.', 'Có một bức tranh treo trên lò sưởi.'),
    ('a6017f3c-68e3-5ebb-815d-a535232885b4', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'show', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/ʃəʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/show-uk.mp3', 'A play, dance, or other entertainment.', 'art show; dog show', 'Arts & Entertainment', 'buổi biểu diễn', 'Một vở kịch, điệu nhảy, hoặc hình thức giải trí khác.', 'triển lãm nghệ thuật; cuộc thi chó'),
    ('68357924-751b-5e6e-a89a-6195ad4898c8', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'sing', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/sɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sing-uk.mp3', 'A gathering at which people sing songs.', '"I really want to sing in the school choir," said Vera.', 'Arts & Entertainment', 'hát', 'Một buổi tụ tập nơi mọi người hát các bài hát.', '"Con thực sự muốn hát trong dàn hợp xướng của trường," Vera nói.'),
    ('8505060f-0ba4-5132-a1b8-23363afaaaa7', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'song', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/sɒŋ/', 'audio/song.mp3', 'A musical composition with lyrics for voice or voices, performed by singing.', 'Thomas listened to his favorite song on the radio yesterday.', 'Arts & Entertainment', 'bài hát', 'Một tác phẩm âm nhạc có lời cho giọng hát hoặc các giọng hát, được trình diễn bằng cách hát.', 'Hôm qua Thomas đã nghe bài hát yêu thích của anh ấy trên radio.'),
    ('731948a6-cc99-558a-8c04-8b17090a44bb', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'spell', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/spɛl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/spell-au.mp3', 'Words or a formula supposed to have magical powers.', 'He cast a spell to cure warts.', 'Arts & Entertainment', 'bùa chú', 'Những từ ngữ hoặc công thức được cho là có sức mạnh ma thuật.', 'Anh ta đọc bùa chú để chữa mụn cóc.'),
    ('b0e1fefc-44ff-566d-9c59-24a708492328', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'star', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/stɑː(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/star-uk.mp3', 'Any small luminous dot appearing in the cloudless portion of the night sky, especially with a fixed location relative to other such dots.', 'Many Hollywood stars attended the launch party.', 'Arts & Entertainment', 'ngôi sao', 'Bất kỳ chấm sáng nhỏ nào xuất hiện ở phần trời quang đãng của bầu trời đêm, đặc biệt có vị trí cố định so với các chấm khác.', 'Nhiều ngôi sao Hollywood đã tham dự bữa tiệc ra mắt.'),
    ('d21d6fde-efd7-558b-b550-62422558c1d2', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'story', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈstɔː.ɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/story-uk.mp3', 'A sequence of real or fictional events; or, an account of such a sequence.', 'The book tells the story of two roommates.', 'Arts & Entertainment', 'câu chuyện', 'Một chuỗi các sự kiện có thật hoặc hư cấu; hoặc, một bản tường thuật về chuỗi sự kiện như vậy.', 'Cuốn sách kể câu chuyện về hai người bạn cùng phòng.'),
    ('c55b025a-a02b-5d39-9684-b76ab8e256ea', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'writer', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɹaɪ.tə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/writer-uk.mp3', 'A person who writes, or produces literary work.', 'Has your girlfriend written you another letter already? She’s quite a writer!', 'Arts & Entertainment', 'nhà văn', 'Người viết, hoặc sản xuất tác phẩm văn học.', 'Bạn gái của bạn đã viết cho bạn một lá thư khác rồi sao? Cô ấy đúng là một nhà văn!'),
    ('6f864b87-25dd-53c4-9b53-500314800165', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'action', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈæk.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/action-us.mp3', 'Something done so as to accomplish a purpose.', 'Knead bread with a rocking action.', 'Sports & Hobbies', 'hành động', 'Việc gì đó được làm để hoàn thành một mục đích.', 'Nhào bột với động tác lắc lư.'),
    ('d1081773-8a0e-5973-8e8c-9ef8f241bfbf', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'activity', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ækˈtɪ.və.ti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/activity-us.mp3', 'The state or quality of being active; activeness.', 'Pit row was abuzz with activity.', 'Sports & Hobbies', 'hoạt động', 'Trạng thái hoặc chất lượng của việc hoạt động; sự năng động.', 'Khu vực Pit row nhộn nhịp với các hoạt động.'),
    ('f29388cb-ab96-5ecf-b68f-460badc8c7fc', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'ball', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/bɔːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ball-au.mp3', 'A solid or hollow sphere, or roughly spherical mass.', 'a ball of spittle; a fecal ball', 'Sports & Hobbies', 'quả bóng', 'Một khối cầu đặc hoặc rỗng, hoặc khối có hình dạng gần như hình cầu.', 'một cục nước bọt; một cục phân'),
    ('9ef1aa0f-3d46-5869-83e0-f45b5d8a0e79', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'bye', 'A1', '["exclam"]'::jsonb, '[{"pos": "exclam", "level": "A1"}]'::jsonb, '/baɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bye-au.mp3', 'The position of a person or team in a tournament or competition who draws no opponent in a particular round so advances to the next round unopposed, or is awarded points for a win in a league table; also the phantom opponent of such a person or team.', 'Craig''s Crew plays the bye next week.', 'Sports & Hobbies', 'tạm biệt', 'Vị trí của một người hoặc đội trong giải đấu hoặc cuộc thi không có đối thủ ở một vòng cụ thể nên tiến thẳng vào vòng tiếp theo hoặc được trao điểm cho một chiến thắng trong bảng xếp hạng giải đấu.', 'Đội Craig''s Crew sẽ được nghỉ ở vòng tới.'),
    ('6e98996b-2816-50f4-a26b-0ef7bbff1d95', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'card', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/kaːd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/card-au.mp3', 'A playing card.', 'He played cards with his friends.', 'Sports & Hobbies', 'lá bài', 'Một quân bài.', 'Anh ấy chơi bài với bạn bè.'),
    ('65765b90-4e0d-52fa-a880-d7c16b7d5140', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'check', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/t͡ʃɛk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/check-us.mp3', 'A situation in which the king is directly threatened by an opposing piece.', 'I don''t know if she will be there, but it''s worth a check.', 'Sports & Hobbies', 'kiểm tra', 'Tình huống trong đó vua bị đe dọa trực tiếp bởi một quân cờ đối phương.', 'Tôi không biết cô ấy có ở đó không, nhưng cũng đáng để kiểm tra.'),
    ('3dda01c2-518e-52de-bd30-ea008ba3c7f6', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'climb', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/klaɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/climb-us.mp3', 'An act of climbing.', 'Prices climbed steeply.', 'Sports & Hobbies', 'leo trèo', 'Hành động leo trèo.', 'Giá cả leo thang dốc.'),
    ('c052db5c-911f-5de7-bcfe-6d0e4836a479', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'club', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/klʌb/', 'https://api.dictionaryapi.dev/media/pronunciations/en/club-us.mp3', 'An association of members joining together for some common purpose, especially sports or recreation.', 'She was sitting in a jazz club, sipping wine and listening to a bass player''s solo.', 'Sports & Hobbies', 'câu lạc bộ, gậy', 'Một hiệp hội của các thành viên cùng nhau tham gia vì một mục đích chung, đặc biệt là thể thao hoặc giải trí.', 'Cô ấy đang ngồi trong một câu lạc bộ nhạc jazz, nhấm nháp rượu và lắng nghe phần độc tấu của một tay chơi bass.'),
    ('e216aa84-45ea-575c-a101-3fe672a7061e', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'draw', 'A1', '["v"]'::jsonb, '[{"pos": "v", "level": "A1"}]'::jsonb, '/dɹɔː/', 'audio/draw.mp3', 'The result of a contest that neither side has won; a tie.', 'The game ended in a draw.', 'Sports & Hobbies', 'hòa, vẽ', 'Kết quả của một cuộc thi mà không bên nào thắng; một trận hòa.', 'Trận đấu kết thúc với tỷ số hòa.'),
    ('1e083808-3700-5bb5-8492-97ddc2f40baf', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'exercise', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ˈɛk.sə.saɪz/', 'audio/exercise.mp3', 'Any activity designed to develop or hone a skill or ability.', 'The teacher told us that the next exercise is to write an essay.', 'Sports & Hobbies', 'bài tập, tập thể dục', 'Bất kỳ hoạt động nào được thiết kế để phát triển hoặc rèn giũa kỹ năng hoặc khả năng.', 'Giáo viên bảo chúng tôi rằng bài tập tiếp theo là viết một bài luận.'),
    ('0f5ef856-37af-51df-bc98-b64cb0ebcba5', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'football', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '[fʷʊʔt̚bɑɫ]', 'https://api.dictionaryapi.dev/media/pronunciations/en/football-au.mp3', '(general) A sport played on foot in which teams attempt to get a ball into a goal or zone defended by the other team.', 'Roman and medieval football matches were more violent than any modern type of football.', 'Sports & Hobbies', 'bóng đá', '(chung) Một môn thể thao chơi trên sân trong đó các đội cố gắng đưa bóng vào khung thành hoặc khu vực do đội kia bảo vệ.', 'Các trận đấu bóng đá La Mã và thời trung cổ bạo lực hơn bất kỳ loại bóng đá hiện đại nào.'),
    ('d2f1268c-f7ab-5966-9abe-c613c12ddcd1', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'fun', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/fʊn/', 'audio/fun.mp3', 'Amusement, enjoyment or pleasure', 'Hey, don''t get bent out of shape over it; I was just funning you.', 'Sports & Hobbies', 'vui vẻ', 'Sự giải trí, thích thú hoặc niềm vui', 'Này, đừng bực bội về nó; tôi chỉ đang đùa với bạn thôi.'),
    ('724e5af1-f1d4-505a-b76e-40ea667e8614', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'game', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ɡeɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/game-us.mp3', 'A playful or competitive activity.', 'He''s in the securities game somehow.', 'Sports & Hobbies', 'trò chơi', 'Một hoạt động vui chơi hoặc cạnh tranh.', 'Anh ta bằng cách nào đó tham gia vào trò chơi chứng khoán.'),
    ('04ab93e9-fcd9-5e9a-acd3-35fcd1457c3b', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'gym', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/dʒɪm/', 'audio/gym.mp3', 'A sports facility specialized for lifting weights and exercise.', 'On Wednesdays I hike; on Fridays I gym.', 'Sports & Hobbies', 'phòng tập thể hình', 'Một cơ sở thể thao chuyên dụng để nâng tạ và tập thể dục.', 'Vào thứ Tư tôi đi bộ đường dài; vào thứ Sáu tôi đi tập gym.'),
    ('93cb7bce-a27a-521e-8c19-c3472291cfed', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'hobby', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈhɒ.bi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hobby-uk.mp3', 'An activity that one enjoys doing in one''s spare time.', 'I like to collect stamps from different countries as a hobby.', 'Sports & Hobbies', 'sở thích', 'Một hoạt động mà người ta thích làm trong thời gian rảnh rỗi.', 'Tôi thích sưu tập tem từ các quốc gia khác nhau như một sở thích.'),
    ('bec4b82c-e20f-51b3-aca5-ccc5ed90a1b3', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'move', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/muːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/move-us.mp3', 'The act of moving; a movement.', 'A slight move of the tiller, and the boat will go off course.', 'Sports & Hobbies', 'di chuyển, nước đi', 'Hành động di chuyển; một chuyển động.', 'Một động tác nhẹ của tay lái, và con thuyền sẽ đi chệch hướng.'),
    ('509f9cb3-99c2-5561-9e9a-67b40ada7e73', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'play', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/pleɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/play-us.mp3', 'Activity for amusement only, especially among the young.', 'Children learn through play.', 'Sports & Hobbies', 'chơi', 'Hoạt động chỉ để giải trí, đặc biệt là trong giới trẻ.', 'Trẻ em học thông qua việc chơi.'),
    ('c1cde0a5-d622-5f17-b1fb-1c669edb15b1', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'player', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpleɪə(ɹ)/', 'audio/player.mp3', 'One that plays', 'He thought he could become a player, at least at the state level.', 'Sports & Hobbies', 'người chơi', 'Người chơi', 'Anh ấy nghĩ mình có thể trở thành một người chơi, ít nhất là ở cấp độ bang.'),
    ('e5165d65-0845-56a9-8c40-810f5c1586b2', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'run', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ɹʊn/', 'audio/run.mp3', 'To run.', 'I just got back from my morning run.', 'Sports & Hobbies', 'chạy', 'Chạy.', 'Tôi vừa trở về sau buổi chạy buổi sáng của mình.'),
    ('68c7f22e-08f8-5a74-9328-a15be04c7b75', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'sport', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/spɔːt/', 'audio/sport.mp3', 'Any activity that uses physical exertion or skills competitively under a set of rules that is not based on aesthetics.', 'Joe was banned from getting legal help. He seemed to view lawsuits as a sport.', 'Sports & Hobbies', 'thể thao', 'Bất kỳ hoạt động nào sử dụng sự gắng sức thể chất hoặc kỹ năng một cách cạnh tranh dưới một bộ quy tắc không dựa trên thẩm mỹ.', 'Joe bị cấm nhận trợ giúp pháp lý. Anh ta dường như xem các vụ kiện như một môn thể thao.'),
    ('ceefc640-4f74-506b-81d7-f1502b2d85fc', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'swim', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/swɪm/', 'audio/swim.mp3', 'An act or instance of swimming.', 'I''m going for a swim.', 'Sports & Hobbies', 'bơi', 'Một hành động hoặc lần bơi.', 'Tôi định đi bơi.'),
    ('88ea1c37-accb-56db-beea-08659c318115', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'team', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/tiːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/team-us.mp3', 'A set of draught animals, such as two horses in front of a carriage.', 'The IT manager leads a team of three software developers.', 'Sports & Hobbies', 'đội, nhóm', 'Một nhóm động vật kéo, chẳng hạn như hai con ngựa trước một cỗ xe.', 'Quản lý CNTT dẫn dắt một nhóm ba nhà phát triển phần mềm.'),
    ('92fa5655-2f31-5e2b-b78a-bd904c4940e7', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'walk', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "A1"}]'::jsonb, '/wɔːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/walk-uk.mp3', 'To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.', 'To walk briskly for an hour every day is to keep fit.', 'Sports & Hobbies', 'đi bộ', 'Di chuyển trên đôi chân bằng cách lần lượt đặt mỗi bàn chân (hoặc cặp hoặc nhóm bàn chân, trong trường hợp động vật có bốn chân trở lên) về phía trước, với ít nhất một chân trên mặt đất mọi lúc. So sánh với chạy.', 'Đi bộ nhanh mỗi ngày một giờ là để giữ dáng.'),
    ('9f9c7528-d017-5851-a4e0-cbd99e92e7ca', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'win', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/wɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/win-uk.mp3', 'To conquer, defeat.', 'to win the jackpot in a lottery; to win a bottle of wine in a raffle', 'Sports & Hobbies', 'chiến thắng', 'Chinh phục, đánh bại.', 'trúng giải độc đắc trong xổ số; trúng một chai rượu vang trong cuộc xổ số'),
    ('284c37b3-2e7d-5c6e-a0c0-b243492813c4', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'theatre', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, NULL, 'audio/theatre.mp3', 'A place or building, consisting of a stage and seating, in which an audience gathers to watch plays, musical performances, public ceremonies, and so on.', 'His grandfather was in the Pacific theater during the war.', 'Arts & Entertainment', 'nhà hát, rạp', 'Một địa điểm hoặc tòa nhà, gồm một sân khấu và chỗ ngồi, nơi khán giả tụ tập để xem kịch, biểu diễn âm nhạc, nghi lễ công cộng, v.v.', 'Ông nội của anh ấy đã ở chiến trường Thái Bình Dương trong chiến tranh.'),
    ('b43f3590-7413-598f-afea-24fdb40cffe3', '43d7a18e-8085-5f9d-abd9-6d5fb12f2353', 'actor', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈæk.tə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/actor-uk.mp3', 'A person who performs, plays a part in a theatrical play or film.', NULL, 'Arts & Entertainment', 'nam diễn viên', 'Người biểu diễn, đóng một vai trong vở kịch sân khấu hoặc phim.', NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

