INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('a03d3ad6-15b3-5415-b08e-f0fc1a84135a', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'address', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/æˈdɹɛs/', 'audio/address.mp3', 'Direction.', 'He addressed some portions of his remarks to his supporters, some to his opponents.', 'Technology & Media', 'địa chỉ', 'Phương hướng.', 'Ông ấy hướng một phần nhận xét của mình đến những người ủng hộ, một phần đến những người phản đối.'),
    ('4dc2f37a-9410-563c-8f99-343342ac1f0d', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'blog', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/blɑɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/blog-us.mp3', 'A website that allows users to reflect, share opinions, and discuss various topics in the form of an online journal, sometimes letting readers comment on their posts. Most blogs are written in a slightly informal tone (personal journals, news, businesses, etc.)', 'This blog was originally posted on my personal site but is reproduced on the forums for greater visibility.', 'Technology & Media', 'blog', 'Một trang web cho phép người dùng suy ngẫm, chia sẻ ý kiến và thảo luận các chủ đề khác nhau dưới dạng nhật ký trực tuyến, đôi khi để người đọc bình luận về bài đăng của họ. Hầu hết các blog được viết hơi...', 'Blog này ban đầu được đăng trên trang cá nhân của tôi nhưng được sao chép trên diễn đàn để có tầm nhìn rộng hơn.'),
    ('cd5e5401-04c9-50f2-b8a4-b6a7dd248750', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'email', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ˈiːmeɪl/', 'audio/email.mp3', 'A system for transferring messages from one computer to another, usually through a network.', 'He sent me his details via email.', 'Technology & Media', 'thư điện tử', 'Một hệ thống chuyển tin nhắn từ máy tính này sang máy tính khác, thường thông qua mạng.', 'Anh ấy đã gửi cho tôi chi tiết của anh ấy qua email.'),
    ('d68f5b0b-407c-54cd-86ab-16ef7bc9f8f6', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'information', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˌɪnfəˈmeɪʃən/', 'audio/information.mp3', 'That which resolves uncertainty; anything that answers the question of "what a given entity is".', 'I need some more information about this issue.', 'Technology & Media', 'thông tin', 'Thứ giải quyết sự không chắc chắn; bất cứ điều gì trả lời câu hỏi "một thực thể nhất định là gì".', 'Tôi cần thêm một số thông tin về vấn đề này.'),
    ('9d6d78c4-b25d-5bd4-91fb-a8690bda3fda', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'internet', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɪntəˌnɛt/', 'audio/internet.mp3', 'Any set of computer networks that communicate using the Internet Protocol. (An intranet.)', 'Do you have internet at your place? My internet is down and I want to check my email.', 'Technology & Media', 'internet', 'Bất kỳ tập hợp mạng máy tính nào giao tiếp bằng Giao thức Internet. (Một mạng nội bộ.)', 'Bạn có internet ở chỗ của bạn không? Internet của tôi bị mất và tôi muốn kiểm tra email.'),
    ('9c44776c-0ad2-5543-b1ed-43de56ba3b03', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'key', 'A1', '["n", "adj", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/kiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/key-uk.mp3', 'An object designed to open and close a lock.', 'The key to solving this problem is persistence.', 'Technology & Media', 'chìa khóa, then chốt', 'Một vật được thiết kế để mở và đóng khóa.', 'Chìa khóa để giải quyết vấn đề này là sự kiên trì.'),
    ('13757a05-d2ed-58cb-94c2-dd475ed539a8', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'machine', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/məˈʃin/', 'https://api.dictionaryapi.dev/media/pronunciations/en/machine-us.mp3', 'A device that directs and controls energy, often in the form of movement or electricity, to produce a certain effect.', 'I called you earlier, but all I got was the machine.', 'Technology & Media', 'máy móc', 'Một thiết bị điều khiển và kiểm soát năng lượng, thường dưới dạng chuyển động hoặc điện, để tạo ra một hiệu ứng nhất định.', 'Tôi đã gọi cho bạn trước đó, nhưng tất cả những gì tôi nhận được là máy.'),
    ('716f1f11-3802-57e7-ad6e-4d0612d9e5a4', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'message', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈmɛsɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/message-us.mp3', 'A communication, or what is communicated; any concept or information conveyed.', 'We''ve just received an urgent message from the President.', 'Technology & Media', 'tin nhắn, thông điệp', 'Một thông tin liên lạc, hoặc điều được truyền đạt; bất kỳ khái niệm hoặc thông tin nào được chuyển tải.', 'Chúng tôi vừa nhận được một tin nhắn khẩn cấp từ Tổng thống.'),
    ('3467652f-efa4-5f68-b098-e4fd64bb141e', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'news', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/njuːz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/news.mp3', 'New information of interest.', 'Is there any news about the storm?', 'Technology & Media', 'tin tức', 'Thông tin mới có giá trị.', 'Có tin tức gì về cơn bão không?'),
    ('89c0f669-d3d3-51c2-ae4a-c8224902393d', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'newspaper', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈnjuːsˌpeɪpə/', 'audio/newspaper.mp3', 'A publication, usually published daily or weekly and usually printed on cheap, low-quality paper, containing news and other articles.', 'She newspapered one end of the room before painting the bookcase.', 'Technology & Media', 'tờ báo', 'Một ấn phẩm, thường được xuất bản hàng ngày hoặc hàng tuần và thường in trên giấy rẻ tiền, chất lượng thấp, chứa tin tức và các bài viết khác.', 'Cô ấy dán báo lên một đầu phòng trước khi sơn giá sách.'),
    ('89bf1e44-0dc0-5eb2-a44c-f2f83f37efda', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'online', 'A1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A1"}, {"pos": "adv", "level": "A1"}]'::jsonb, '/ɒnˈlaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/online.mp3', 'To bring (a system, etc.) online; to promote to an active or running state.', 'I prefer to read online newspapers.', 'Technology & Media', 'trực tuyến', 'Để đưa (một hệ thống, v.v.) trực tuyến; để chuyển sang trạng thái hoạt động hoặc đang chạy.', 'Tôi thích đọc báo trực tuyến hơn.'),
    ('ac69a877-d717-5fc9-9394-8ead2c45e0f8', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'photograph', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈfəʊ.tə.ˌɡɹɑːf/', 'audio/photograph.mp3', 'A picture created by projecting an image onto a photosensitive surface such as a chemically treated plate or film, CCD receptor, etc.', 'She photographs well. The camera loves her.', 'Technology & Media', 'bức ảnh, chụp ảnh', 'Một bức tranh được tạo ra bằng cách chiếu hình ảnh lên một bề mặt nhạy sáng như một tấm hoặc phim đã qua xử lý hóa học, bộ thu CCD, v.v.', 'Cô ấy chụp ảnh rất đẹp. Máy ảnh yêu cô ấy.'),
    ('3a8e93d8-ec78-5a00-94b0-df04a28bf760', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'programme', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈpɹəʊɡɹæm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/programme-uk.mp3', 'A set of structured activities.', 'Our program for today’s exercise class includes swimming and jogging.', 'Technology & Media', 'chương trình', 'Một tập hợp các hoạt động có cấu trúc.', 'Chương trình của lớp thể dục hôm nay của chúng tôi bao gồm bơi lội và chạy bộ.'),
    ('ee9c198c-cbd3-5bbe-87ab-1f3cee2ea68e', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'radio', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈɹeɪdiˌəʊ/', 'audio/radio.mp3', 'The technology that allows for the transmission of sound or other signals by modulation of electromagnetic waves.', 'I think the boat is sinking; we''d better radio for help. / I radioed him already. / Radio the coordinates this time. / OK. I radioed them the coordinates.', 'Technology & Media', 'radio', 'Công nghệ cho phép truyền âm thanh hoặc các tín hiệu khác bằng cách điều chế sóng điện từ.', 'Tôi nghĩ con thuyền đang chìm; tốt hơn hết chúng ta nên gọi cứu hộ bằng radio. / Tôi đã liên lạc với anh ấy bằng radio rồi. / Lần này hãy gửi tọa độ bằng radio. / Được rồi. Tôi đã gửi tọa độ cho họ bằng radio.'),
    ('3a7ca052-6c4e-5ca6-9045-6ba3255ce760', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'television', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈtɛləˌvɪʒən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/television-uk.mp3', 'An electronic communication medium that allows the transmission of real-time visual images, and often sound.', 'It’s a good thing that television doesn’t transmit smell.', 'Technology & Media', 'tivi', 'Một phương tiện truyền thông điện tử cho phép truyền hình ảnh trực quan và thường là âm thanh theo thời gian thực.', 'Thật tốt là tivi không truyền tải mùi hương.'),
    ('aa7df07b-6865-5e2d-8022-757f91aeb927', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'text', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A2"}]'::jsonb, '/tɛkst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/text-us.mp3', 'A writing consisting of multiple glyphs, characters, symbols or sentences.', 'German text', 'Technology & Media', 'văn bản, nhắn tin', 'Một bản viết bao gồm nhiều ký tự, chữ cái, biểu tượng hoặc câu.', 'Văn bản tiếng Đức'),
    ('3da06105-0dea-5741-8c68-75a75efa7476', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'business', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈbɪd.nəs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/business-us.mp3', 'A specific commercial enterprise or establishment.', 'I was left my father''s business.', 'Business & Economy', 'kinh doanh', 'Một doanh nghiệp hoặc cơ sở thương mại cụ thể.', 'Tôi được thừa kế doanh nghiệp của cha tôi.'),
    ('3a48f525-9dc8-5dc4-b8dc-3e1af2eb706d', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'capital', 'A1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "adj", "level": "A1"}]'::jsonb, '/ˈkæp.ɪ.təl/', 'audio/capital.mp3', 'Already-produced durable goods available for use as a factor of production, such as steam shovels (equipment) and office buildings (structures).', 'He does not have enough capital to start a business.', 'Business & Economy', 'vốn', 'Hàng hóa bền đã sản xuất sẵn có để sử dụng như một yếu tố sản xuất, chẳng hạn như máy xúc hơi nước (thiết bị) và tòa nhà văn phòng (công trình).', 'Anh ấy không có đủ vốn để bắt đầu một doanh nghiệp.'),
    ('1aca64a7-a639-5afc-91a4-fef32d986635', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'company', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/ˈkʌmp(ə)ni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/company-uk.mp3', 'A team; a group of people who work together professionally.', 'Keep the house clean; I have company coming.', 'Business & Economy', 'công ty', 'Một đội; một nhóm người làm việc cùng nhau chuyên nghiệp.', 'Giữ nhà sạch sẽ; tôi có khách sắp đến.'),
    ('af61b0f9-9608-5609-9208-60517dfa143c', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'interest', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ˈɪntəɹɪst/', 'audio/interest.mp3', 'The price paid for obtaining, or price received for providing, money or goods in a credit transaction, calculated as a fraction of the amount or value of what was borrowed.', 'Our bank offers borrowers an annual interest of 5%.', 'Business & Economy', 'lãi suất', 'Giá phải trả để có được, hoặc giá nhận được để cung cấp, tiền hoặc hàng hóa trong một giao dịch tín dụng, được tính như một phần của số tiền hoặc giá trị của những gì đã vay.', 'Ngân hàng của chúng tôi cung cấp cho người vay mức lãi suất hàng năm là 5%.'),
    ('b7600c61-3c66-5622-bc3e-af6227a6e142', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'make', 'A1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/meɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/make-uk.mp3', 'Brand or kind; model.', 'What make of car do you drive?', 'Business & Economy', 'nhãn hiệu, sản xuất', 'Nhãn hiệu hoặc loại; kiểu mẫu.', 'Bạn lái xe hiệu gì?'),
