    ('03a7b76a-ae29-5c68-b537-5c68160be554', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'interview', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/ˈɪntəvjuː/', 'audio/interview.mp3', 'An official face-to-face meeting of monarchs or other important figures.', 'The reporter gave the witness an interview.', 'Work & Career', 'phỏng vấn', 'Một cuộc gặp mặt chính thức giữa các nguyên thủ quốc gia hoặc các nhân vật quan trọng khác.', 'Phóng viên đã phỏng vấn nhân chứng.'),
    ('2d93af7f-7c6a-5865-974e-b5190bddcdd4', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'job', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/d͡ʒɒb/', 'https://api.dictionaryapi.dev/media/pronunciations/en/job-uk.mp3', 'A task.', 'A job half done is hardly done at all.', 'Work & Career', 'công việc', 'Một nhiệm vụ.', 'Công việc làm nửa vời thì hầu như chưa hoàn thành.'),
