    ('432cc244-649b-52b5-b4f5-68ea86de1a50', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'magazine', 'A1', '["n"]'::jsonb, '[{"pos": "n", "level": "A1"}]'::jsonb, '/mæɡəˈziːn/', 'audio/magazine.mp3', 'A non-academic periodical publication, generally consisting of sheets of paper folded in half and stapled at the fold.', NULL, 'Technology & Media', 'tạp chí', 'Một ấn phẩm định kỳ không mang tính học thuật, thường bao gồm các tờ giấy được gấp đôi và ghim ở nếp gấp.', NULL),
    ('ca25bf73-db97-5e93-923d-ee048afb324e', 'db34714b-a79e-526c-b22a-3d83ffb9f996', 'phone', 'A1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A1"}, {"pos": "v", "level": "A1"}]'::jsonb, '/fəʊ̯n/', 'https://api.dictionaryapi.dev/media/pronunciations/en/phone-uk.mp3', 'A device for transmitting conversations and other sounds in real time across distances, now often a small portable unit also capable of running software etc.', NULL, 'Technology & Media', 'điện thoại', 'Một thiết bị để truyền tải cuộc trò chuyện và các âm thanh khác trong thời gian thực qua khoảng cách, ngày nay thường là một thiết bị di động nhỏ cũng có khả năng chạy phần mềm, v.v.', NULL)
